import { useState, useEffect, useRef } from "react";

const questions = [
  // BIOLOGY - BOTANY (1-45)
  { id: 1, subject: "Biology", section: "Botany", q: "In the Calvin cycle (C3 pathway), the first stable product of CO₂ fixation is:", options: ["Oxaloacetate (OAA)", "3-Phosphoglycerate (3-PGA)", "Glyceraldehyde-3-phosphate (G3P)", "Ribulose-1,5-bisphosphate (RuBP)"], ans: 1, exp: "CO₂ combines with RuBP (5C) via RuBisCO enzyme → unstable 6C compound → 2 molecules of 3-PGA (3C). 3-PGA is the first STABLE product in C3 plants. In C4 plants, OAA is the first stable product. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 2, subject: "Biology", section: "Botany", q: "Kranz anatomy is a characteristic structural feature of:", options: ["C3 plants", "CAM plants", "C4 plants", "Hydrophytes"], ans: 2, exp: "Kranz anatomy in C4 plants: mesophyll cells surrounding bundle sheath cells in a wreath-like arrangement. Bundle sheath cells have large chloroplasts (without grana) where Calvin cycle occurs. Examples: Sugarcane, Maize. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 3, subject: "Biology", section: "Botany", q: "Which of the following is a macro-element essential for plants but is a component of chlorophyll?", options: ["Iron (Fe)", "Zinc (Zn)", "Magnesium (Mg)", "Molybdenum (Mo)"], ans: 2, exp: "Magnesium (Mg) is a macro-element (required in large amounts) and is the central atom of the chlorophyll molecule (porphyrin ring). Also activates many enzymes. Fe is a micro-element involved in chlorophyll synthesis. NCERT Class 11, Ch 12.", stars: 5 },
  { id: 4, subject: "Biology", section: "Botany", q: "Abscisic acid (ABA) promotes all of the following EXCEPT:", options: ["Stomatal closure", "Seed dormancy", "Leaf senescence", "Stem elongation"], ans: 3, exp: "ABA functions: (1) closes stomata during water stress, (2) promotes seed dormancy, (3) promotes leaf senescence and abscission, (4) inhibits germination. Stem elongation is promoted by GIBBERELLINS (GA₃), NOT ABA. NCERT Class 11, Ch 15.", stars: 5 },
  { id: 5, subject: "Biology", section: "Botany", q: "In nitrogen fixation by Rhizobium, the enzyme nitrogenase is protected from oxygen by:", options: ["Nitrate reductase", "Leghemoglobin", "Ferredoxin", "Nitrogenase reductase"], ans: 1, exp: "Leghemoglobin (a pink pigment) is present in root nodules and acts as an O₂ scavenger — it keeps the nodule micro-aerobic, protecting nitrogenase (which is irreversibly inactivated by O₂). It gives root nodules their pink/red colour. NCERT Class 11, Ch 12.", stars: 5 },
  { id: 6, subject: "Biology", section: "Botany", q: "The net gain of ATP molecules per glucose in glycolysis (cytoplasm only) is:", options: ["38", "8", "2", "4"], ans: 2, exp: "Glycolysis: Glucose → 2 Pyruvate. Investment phase: 2 ATP used. Pay-off phase: 4 ATP produced. Net gain = 4 − 2 = 2 ATP + 2 NADH. (Total aerobic = 36–38 ATP but glycolysis alone = 2 ATP net). NCERT Class 11, Ch 14.", stars: 4 },
  { id: 7, subject: "Biology", section: "Botany", q: "Photorespiration occurs in C3 plants when RuBisCO acts on:", options: ["CO₂ (carboxylation)", "O₂ (oxygenation)", "H₂O", "NADPH"], ans: 1, exp: "Photorespiration: At high O₂/low CO₂ conditions, RuBisCO uses O₂ instead of CO₂ → RuBP + O₂ → phosphoglycolate (2C) + 3-PGA. Phosphoglycolate is a wasteful product. C4 plants avoid photorespiration by concentrating CO₂ in bundle sheath via PEP carboxylase. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 8, subject: "Biology", section: "Botany", q: "Which of the following is NOT correctly matched?", options: ["Auxin — promotes cell elongation", "Cytokinin — delays leaf senescence", "Ethylene — promotes fruit ripening", "Gibberellin — promotes root initiation"], ans: 3, exp: "Gibberellin promotes stem elongation, flowering in LDP, breaking dormancy, parthenocarpy — NOT root initiation. Root initiation (adventitious roots) is promoted by AUXIN (IAA). NCERT Class 11, Ch 15.", stars: 5 },
  { id: 9, subject: "Biology", section: "Botany", q: "Totipotency was first demonstrated using:", options: ["Pollen grains", "Single leaf cells of tobacco", "Carrot phloem parenchyma cells", "Onion root tip cells"], ans: 2, exp: "F.C. Steward (1950s) demonstrated totipotency by culturing carrot phloem parenchyma cells → callus → complete carrot plant on appropriate media (auxin + cytokinin). This formed the basis of plant tissue culture. NCERT Class 11, Ch 15.", stars: 5 },
  { id: 10, subject: "Biology", section: "Botany", q: "In angiosperms, double fertilization results in formation of:", options: ["Seed and fruit", "Zygote (2n) and primary endosperm nucleus (3n)", "Two zygotes", "Endosperm (2n) and embryo (3n)"], ans: 1, exp: "Double fertilization (unique to angiosperms): One male gamete (n) + egg cell (n) → zygote (2n) → embryo. Second male gamete (n) + 2 polar nuclei (n+n) → primary endosperm nucleus (3n, triploid) → endosperm. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 11, subject: "Biology", section: "Botany", q: "The phenomenon of apomixis in plants refers to:", options: ["Vegetative propagation", "Formation of seeds without fertilization", "Cross pollination", "Germination of seeds in darkness"], ans: 1, exp: "Apomixis: formation of seeds (embryo) without fertilization. Types: (1) Agamospermy — embryo from unfertilized egg, (2) Vegetative apomixis — bulbils, etc. Advantage: preserves superior hybrid traits. Used in agriculture to maintain hybrid vigor. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 12, subject: "Biology", section: "Botany", q: "The gametophyte in angiosperms is represented by:", options: ["Pollen grain and embryo sac", "Ovule and anther", "Seed and fruit", "Stem and leaf"], ans: 0, exp: "Alternation of generations: Sporophyte (2n, dominant in angiosperms) produces spores → gametophyte (n, reduced). Male gametophyte = mature pollen grain (3-celled). Female gametophyte = embryo sac (8-nucleate, 7-celled). NCERT Class 12, Ch 2.", stars: 4 },
  { id: 13, subject: "Biology", section: "Botany", q: "Water potential (Ψw) is expressed as:", options: ["Ψw = Ψs + Ψp", "Ψw = Ψs − Ψp", "Ψw = Ψp − Ψs", "Ψw = Ψs × Ψp"], ans: 0, exp: "Water potential: Ψw = Ψs (solute/osmotic potential, always negative) + Ψp (pressure potential, can be positive or negative). Pure water: Ψw = 0. NCERT Class 11, Ch 11.", stars: 5 },
  { id: 14, subject: "Biology", section: "Botany", q: "Companion cells are associated with which vascular tissue and help in:", options: ["Xylem; water transport", "Phloem; loading and unloading of sugars", "Xylem; mineral transport", "Phloem; water storage"], ans: 1, exp: "Companion cells (in phloem) have dense cytoplasm and many mitochondria. They assist sieve tube elements (which lack nucleus) by: (1) loading sucrose into sieve tubes from mesophyll (source), (2) unloading at sink tissue. NCERT Class 11, Ch 6.", stars: 4 },
  { id: 15, subject: "Biology", section: "Botany", q: "In Mendelian genetics, the principle of dominance states that:", options: ["Both alleles are equally expressed in F1", "In F1, only one allele (dominant) is expressed; the other (recessive) is masked", "Both traits blend in F1", "Each trait is controlled by two genes"], ans: 1, exp: "Mendel's 1st Law (Principle of Dominance): When two plants with contrasting characters are crossed, only one character (dominant) appears in F1. The other (recessive) is masked but not lost — it reappears in F2 in 1/4 progeny. NCERT Class 12, Ch 5.", stars: 4 },
  { id: 16, subject: "Biology", section: "Botany", q: "Transpiration pull (cohesion-tension theory) for ascent of sap was proposed by:", options: ["Dixon & Joly", "Munch", "Priestley", "Strasburger"], ans: 0, exp: "Dixon & Joly (1894) proposed the Cohesion-Tension theory: (1) Cohesion of water molecules (H-bonding), (2) Adhesion to xylem walls, (3) Transpiration pull creates tension. Munch proposed pressure flow hypothesis for phloem transport. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 17, subject: "Biology", section: "Botany", q: "The correct sequence of cell cycle phases is:", options: ["G₁ → S → G₂ → M", "M → G₁ → S → G₂", "S → G₁ → G₂ → M", "G₁ → G₂ → S → M"], ans: 0, exp: "Cell cycle: Interphase (G₁ + S + G₂) + Mitotic phase (M). G₁: cell growth; S: DNA synthesis/replication; G₂: preparation for division; M: mitosis (PMAT). NCERT Class 11, Ch 10.", stars: 5 },
  { id: 18, subject: "Biology", section: "Botany", q: "During meiosis I, the homologous chromosomes separate. This stage is:", options: ["Metaphase I", "Anaphase I", "Telophase I", "Prophase I"], ans: 1, exp: "Meiosis I (reductional division): Prophase I (synapsis, crossing over) → Metaphase I (bivalents at equatorial plate) → Anaphase I (homologous chromosomes separate to poles) → Telophase I. Anaphase I reduces chromosome number from 2n to n. NCERT Class 11, Ch 10.", stars: 4 },
  { id: 19, subject: "Biology", section: "Botany", q: "Which feature of the nucleus was first described to contain DNA?", options: ["Nucleolus", "Nuclear pore", "Chromatin", "Nuclear envelope"], ans: 2, exp: "Chromatin = DNA + histone proteins (H1, H2A, H2B, H3, H4). 2 copies each of H2A, H2B, H3, H4 form histone octamer → nucleosome (146 bp DNA wrapped around). H1 binds linker DNA. NCERT Class 11, Ch 8.", stars: 4 },
  { id: 20, subject: "Biology", section: "Botany", q: "Pollination by wind is called:", options: ["Entomophily", "Anemophily", "Hydrophily", "Ornithophily"], ans: 1, exp: "Pollination types: Anemophily (wind) — light, non-sticky pollen, feathery stigma; Entomophily (insects) — colourful, fragrant, sticky pollen; Hydrophily (water) — e.g., Vallisneria, Hydrilla; Ornithophily (birds); Chiropterophily (bats). NCERT Class 12, Ch 2.", stars: 4 },
  { id: 21, subject: "Biology", section: "Botany", q: "In angiosperms, the endosperm nucleus is:", options: ["Diploid (2n)", "Haploid (n)", "Triploid (3n)", "Tetraploid (4n)"], ans: 2, exp: "Primary endosperm nucleus (PEN): formed by fusion of one male gamete (n) + 2 polar nuclei (n+n) = 3n (triploid). Endosperm provides nutrition to developing embryo. In coconut, liquid endosperm = coconut water; solid = coconut meat. NCERT Class 12, Ch 2.", stars: 5 },
  { id: 22, subject: "Biology", section: "Botany", q: "The microsporogenesis leads to formation of which cells?", options: ["Megaspores", "Microspores (pollen grains)", "Embryo sac", "Seeds"], ans: 1, exp: "Microsporogenesis: Microspore mother cell (MMC, 2n) → Meiosis → 4 microspores (n) → pollen grains. Occurs in anther loculi. Megasporogenesis: Megaspore mother cell (MMC) → Meiosis → 4 megaspores → only 1 functional megaspore → embryo sac. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 23, subject: "Biology", section: "Botany", q: "Which plant group shows alternation of generations with dominant gametophyte?", options: ["Angiosperms", "Gymnosperms", "Bryophytes", "Pteridophytes"], ans: 2, exp: "Alternation of generations: Bryophytes — gametophyte (n) dominant, sporophyte (2n) dependent. Pteridophytes — sporophyte dominant, gametophyte independent (prothallus). Gymnosperms & Angiosperms — sporophyte dominant, gametophyte highly reduced. NCERT Class 11, Ch 3.", stars: 4 },
  { id: 24, subject: "Biology", section: "Botany", q: "Assertion: Gymnosperms are called naked-seed plants. Reason: Their ovules/seeds are NOT enclosed in a fruit.", options: ["Both A and R are true, and R is the correct explanation of A", "Both A and R are true, but R is NOT the correct explanation", "A is true, R is false", "A is false, R is true"], ans: 0, exp: "Gymnosperms (gymnos=naked, sperma=seed): ovules are born on open megasporophylls (not enclosed in ovary). Hence NO fruit is formed. Examples: Cycas, Pinus, Ginkgo. NCERT Class 11, Ch 3.", stars: 4 },
  { id: 25, subject: "Biology", section: "Botany", q: "Which of the following is a correct example of a fruit developing from non-ovary tissue (false fruit)?", options: ["Mango", "Tomato", "Apple", "Grape"], ans: 2, exp: "True fruit: developed from ovary wall (pericarp). False fruit (pseudocarp): develops from thalamus or other parts. Apple: edible fleshy part = swollen thalamus; actual fruit (core) = ovary. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 26, subject: "Biology", section: "Botany", q: "Vascular bundles in monocot stems are:", options: ["Open and arranged in a ring", "Closed and scattered throughout the ground tissue", "Open and scattered", "Closed and arranged in a ring"], ans: 1, exp: "Monocot stem: vascular bundles are conjoint collateral CLOSED (no cambium) and scattered throughout ground tissue (atactostele). Dicot stem: open bundles (with cambium), arranged in a ring (eustele). NCERT Class 11, Ch 6.", stars: 4 },
  { id: 27, subject: "Biology", section: "Botany", q: "Pneumatophores are present in:", options: ["Mesophytes", "Mangrove plants (halophytes)", "Desert plants (xerophytes)", "Hydrophytes"], ans: 1, exp: "Pneumatophores = breathing roots (respiratory roots) of mangroves (e.g., Rhizophora, Avicennia). They grow vertically upward from soil (negative geotropism) to facilitate gaseous exchange in waterlogged, oxygen-poor soil. NCERT Class 11, Ch 5.", stars: 4 },
  { id: 28, subject: "Biology", section: "Botany", q: "The enzyme responsible for CO₂ fixation in the dark reaction of photosynthesis in C3 plants is:", options: ["PEP carboxylase", "RuBisCO (ribulose-1,5-bisphosphate carboxylase/oxygenase)", "ATP synthase", "NADP reductase"], ans: 1, exp: "RuBisCO is the most abundant protein on Earth. In C3 plants, RuBisCO fixes CO₂ onto RuBP in mesophyll cells. In C4 plants, INITIAL fixation is by PEP carboxylase in mesophyll; then RuBisCO in bundle sheath cells. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 29, subject: "Biology", section: "Botany", q: "Phytochrome exists in two interconvertible forms. Pfr promotes flowering in:", options: ["Short day plants (SDP)", "Long day plants (LDP)", "Day-neutral plants", "All flowering plants equally"], ans: 1, exp: "Phytochrome: Pr (660nm red light) ↔ Pfr (730nm far-red light, active form). Pfr promotes flowering in LDP (e.g., Wheat, Barley, Spinach) — requires long periods of light. In SDP (e.g., Tobacco, Soybean), Pfr INHIBITS flowering. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 30, subject: "Biology", section: "Botany", q: "Plasmolysis occurs when a cell is placed in:", options: ["Hypotonic solution", "Hypertonic solution", "Isotonic solution", "Distilled water"], ans: 1, exp: "Plasmolysis: In hypertonic solution, water moves out of cell by osmosis (exosmosis) → cell membrane shrinks away from cell wall → plasmolysis. Turgor pressure falls to zero → incipient plasmolysis. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 31, subject: "Biology", section: "Botany", q: "The sigmoid (S-shaped) growth curve in plants is described by which growth phase sequence?", options: ["Lag → Exponential → Stationary → Decline", "Exponential → Lag → Stationary", "Lag → Log → Decline", "Stationary → Log → Lag"], ans: 0, exp: "Plant growth curve: Lag phase (slow, cell division starts) → Exponential/Log phase (rapid cell division and elongation) → Stationary phase (maturation, growth rate slows) → Decline (senescence). NCERT Class 11, Ch 15.", stars: 4 },
  { id: 32, subject: "Biology", section: "Botany", q: "Casparian strips are present in:", options: ["Epidermis", "Endodermis of roots", "Cortex", "Pericycle"], ans: 1, exp: "Casparian strips: Suberin-impregnated bands on radial and transverse walls of endodermal cells. They prevent apoplastic movement of water and minerals into the stele — all water and solutes MUST pass through symplast (through cell membrane), enabling selective uptake. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 33, subject: "Biology", section: "Botany", q: "Which of the following is the correct product of light reactions of photosynthesis?", options: ["Glucose, O₂, CO₂", "ATP, NADPH, O₂", "3-PGA, G3P", "CO₂, H₂O, ATP"], ans: 1, exp: "Light reactions (thylakoid membrane): Light energy → ATP (cyclic/non-cyclic photophosphorylation) + NADPH (by PS I & PS II) + O₂ (from water splitting/photolysis). These are used in dark reactions (Calvin cycle) to fix CO₂. NCERT Class 11, Ch 13.", stars: 5 },
  { id: 34, subject: "Biology", section: "Botany", q: "Which gas is produced in plants under anaerobic conditions (anaerobic respiration)?", options: ["CO₂ only", "Ethanol + CO₂", "Lactic acid only", "O₂"], ans: 1, exp: "Fermentation (anaerobic respiration) in plants/yeast: Pyruvate → Acetaldehyde (CO₂ released) → Ethanol. In mammals: Pyruvate → Lactate (lactic acid). Net ATP in fermentation = 2 (only glycolysis). NCERT Class 11, Ch 14.", stars: 4 },
  { id: 35, subject: "Biology", section: "Botany", q: "Senescence in plants is delayed by:", options: ["ABA", "Ethylene", "Cytokinin", "IAA"], ans: 2, exp: "Cytokinin (e.g., kinetin, zeatin): synthesized in roots, promotes cell division, delays senescence (Richmond-Lang effect — keeps leaves green by mobilizing nutrients). ABA and ethylene PROMOTE senescence. NCERT Class 11, Ch 15.", stars: 5 },
  { id: 36, subject: "Biology", section: "Botany", q: "Pollen grains have a tough outer wall called exine made of:", options: ["Cellulose", "Sporopollenin", "Lignin", "Pectin"], ans: 1, exp: "Exine = outer layer of pollen wall, composed of sporopollenin (most resistant biological material known — resistant to high temperatures, acids, alkalis, enzymes). Hence pollen grains are well preserved as fossils. Intine = inner layer of cellulose and pectin. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 37, subject: "Biology", section: "Botany", q: "Which of the following represents a fibrous root system?", options: ["Carrot", "Radish", "Wheat", "Turnip"], ans: 2, exp: "Fibrous root system: characteristic of monocots. Adventitious roots from base of stem, similar in size. Examples: Wheat, Maize, Grass, Sugarcane. Tap root system: characteristic of dicots, primary root persists. Examples: Carrot, Radish, Turnip (modified tap roots). NCERT Class 11, Ch 5.", stars: 4 },
  { id: 38, subject: "Biology", section: "Botany", q: "The quantum yield is maximum for which colour of light in photosynthesis?", options: ["Green light", "Blue light", "Red light", "Yellow light"], ans: 2, exp: "Red light (680nm, PS II & PS I) gives maximum quantum yield in photosynthesis. Green light is least effective (most reflected — that's why plants appear green). Emerson's enhancement effect: Red + Far-red light together give more photosynthesis than either alone. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 39, subject: "Biology", section: "Botany", q: "Seed germination requires all of the following EXCEPT:", options: ["Water", "Adequate temperature", "Light (always required)", "Oxygen"], ans: 2, exp: "Seed germination requirements: (1) Water (imbibition activates enzymes), (2) Optimal temperature, (3) O₂ (for aerobic respiration to provide energy). Light is NOT always required — many seeds are light-neutral. Some seeds need light (positively photoblastic: lettuce), others inhibited by light (negatively photoblastic: onion). NCERT Class 11, Ch 15.", stars: 4 },
  { id: 40, subject: "Biology", section: "Botany", q: "Parthenocarpy results in formation of:", options: ["Seedless fruits", "Seed without fruit", "Double seeds", "Multiple fruits"], ans: 0, exp: "Parthenocarpy: fruit development without fertilization → seedless fruits. Induced by: (1) Gibberellins spray (e.g., seedless grapes, tomato), (2) Auxin spray. Natural parthenocarpy: Banana, Seedless watermelon. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 41, subject: "Biology", section: "Botany", q: "Guard cells regulate transpiration by controlling:", options: ["Root pressure", "Stomatal opening and closing", "Leaf area", "Cuticle thickness"], ans: 1, exp: "Guard cells: kidney-shaped (dicots) or dumbbell-shaped (monocots/grasses). Opening: K⁺ ions enter guard cells → water follows → guard cells swell → stomata open. Closing: K⁺ exit → water follows → stomata close. ABA triggers stomatal closure under drought stress. NCERT Class 11, Ch 11.", stars: 4 },
  { id: 42, subject: "Biology", section: "Botany", q: "Herbaceous plants with reticulate venation belong to:", options: ["Monocotyledons", "Dicotyledons", "Gymnosperms", "Pteridophytes"], ans: 1, exp: "Dicot characters: reticulate (net) venation, tap root, two cotyledons, tetramerous/pentamerous flowers, open vascular bundles. Monocot characters: parallel venation, fibrous roots, one cotyledon, trimerous flowers, closed vascular bundles. NCERT Class 11, Ch 5.", stars: 4 },
  { id: 43, subject: "Biology", section: "Botany", q: "The process of vernalization involves:", options: ["Treatment with red light", "Exposure to low temperature to accelerate flowering", "Application of gibberellin", "Removal of leaves before flowering"], ans: 1, exp: "Vernalization: exposure to cold temperature (0-10°C for several weeks) to fulfil requirement for flowering (acceleration of flowering). Examples: Winter wheat, Rye, Beet. Eliminates/reduces vegetative phase. Site of perception: shoot apex. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 44, subject: "Biology", section: "Botany", q: "In the process of photorespiration, the glycolate formed in the chloroplast is oxidized in:", options: ["Mitochondria", "Peroxisome", "Glyoxisome", "Vacuole"], ans: 1, exp: "Photorespiration pathway: Chloroplast (RuBP + O₂ → phosphoglycolate → glycolate) → Peroxisome (glycolate oxidized → glyoxylate → glycine) → Mitochondria (2 glycine → serine + CO₂ + NH₃) → Peroxisome → Chloroplast. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 45, subject: "Biology", section: "Botany", q: "Protoplast fusion for somatic hybridization involves removal of cell wall using:", options: ["Cellulase and pectinase", "Amylase and lipase", "Protease and nuclease", "Lysozyme"], ans: 0, exp: "Somatic hybridization (parasexual hybridization): (1) Remove cell wall using cellulase + pectinase → protoplasts; (2) Fuse protoplasts using PEG (polyethylene glycol) or electrofusion; (3) Culture → somatic hybrid. Example: Pomato (Potato + Tomato). NCERT Class 12, Ch 9.", stars: 4 },

  // BIOLOGY - ZOOLOGY (46-90)
  { id: 46, subject: "Biology", section: "Zoology", q: "The proton gradient across the inner mitochondrial membrane drives ATP synthesis by:", options: ["Substrate-level phosphorylation", "Oxidative phosphorylation via ATP synthase (chemiosmosis)", "Fermentation", "GTP hydrolysis"], ans: 1, exp: "Mitchell's chemiosmotic hypothesis: NADH/FADH₂ → electron transport chain → proton (H⁺) pumped from matrix to intermembrane space → proton gradient (electrochemical) → H⁺ flows back through ATP synthase (F₀F₁) → ATP synthesis. NCERT Class 11, Ch 14.", stars: 5 },
  { id: 47, subject: "Biology", section: "Zoology", q: "Which structure in the male reproductive system produces testosterone?", options: ["Sertoli cells", "Leydig cells (interstitial cells)", "Spermatogonia", "Epididymis"], ans: 1, exp: "Leydig cells: present in interstitial spaces between seminiferous tubules; secrete testosterone (androgen). Sertoli cells: inside seminiferous tubules; nurse cells; secrete inhibin (inhibits FSH) and maintain blood-testis barrier. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 48, subject: "Biology", section: "Zoology", q: "In the Krebs cycle, how many molecules of CO₂ are released per acetyl-CoA?", options: ["1", "2", "3", "4"], ans: 1, exp: "Krebs cycle (per acetyl-CoA, 2C): 2 CO₂ released (at isocitrate dehydrogenase and α-ketoglutarate dehydrogenase steps). Per glucose: 2 acetyl-CoA → 4 CO₂. Also produced: 3 NADH + 1 FADH₂ + 1 GTP per acetyl-CoA. NCERT Class 11, Ch 14.", stars: 5 },
  { id: 49, subject: "Biology", section: "Zoology", q: "Normal sperm count in human semen for fertility is:", options: ["Less than 5 million/mL", "More than 40 million/mL (≥40 million/mL)", "Exactly 10 million/mL", "200 million/mL"], ans: 1, exp: "Normal semen parameters (WHO): Volume 2–5 mL, sperm count ≥40 million/mL (≥15 million/mL by newer WHO criteria), motility ≥40%, morphology ≥4% normal. Oligospermia <15 million/mL. Azoospermia = no sperms. NCERT Class 12, Ch 3.", stars: 4 },
  { id: 50, subject: "Biology", section: "Zoology", q: "The corpus luteum in ovary secretes primarily:", options: ["Estrogen only", "Progesterone (and some estrogen)", "FSH", "LH"], ans: 1, exp: "After ovulation: ruptured Graafian follicle → corpus luteum (yellow body). Corpus luteum secretes: mainly PROGESTERONE + some estrogen. Progesterone maintains endometrium for implantation, prepares mammary glands, suppresses further ovulation. If no fertilization, corpus luteum degenerates → corpus albicans. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 51, subject: "Biology", section: "Zoology", q: "The genetic disease in which individuals have XXY genotype is:", options: ["Turner's syndrome", "Klinefelter's syndrome", "Down's syndrome", "Edward's syndrome"], ans: 1, exp: "Klinefelter's syndrome: 47 chromosomes, XXY (2n=47). Males with extra X. Features: tall stature, gynaecomastia, reduced facial/body hair, infertility, low IQ. Turner's syndrome: 45 chromosomes, XO (2n=45), female with streak gonads, short stature, sterile. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 52, subject: "Biology", section: "Zoology", q: "ABO blood group system is controlled by gene I with three alleles. The phenotype O is produced by genotype:", options: ["IAIA", "IAIB", "IBIB", "ii"], ans: 3, exp: "ABO blood groups: A = IAIA or IAi, B = IBIB or IBi, AB = IAIB (co-dominance), O = ii (recessive). IA and IB are co-dominant and both dominant over i. This is an example of multiple allelism. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 53, subject: "Biology", section: "Zoology", q: "Haemophilia A is caused by deficiency of:", options: ["Factor IX", "Factor VIII", "Platelet count", "Vitamin K"], ans: 1, exp: "Haemophilia A: X-linked recessive disorder. Deficiency of clotting factor VIII (anti-haemophilic factor). 'Royal disease' (Queen Victoria was carrier). Haemophilia B: deficiency of factor IX (Christmas factor). Affected males bleed profusely. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 54, subject: "Biology", section: "Zoology", q: "In which part of the digestive system does maximum absorption of nutrients occur?", options: ["Stomach", "Large intestine", "Small intestine (jejunum and ileum)", "Oesophagus"], ans: 2, exp: "Small intestine has villi and microvilli (brush border) → enormous surface area for absorption. Duodenum receives bile + pancreatic juice. Jejunum and ileum: glucose, amino acids, fatty acids, vitamins absorbed. Large intestine: water and electrolyte absorption only. NCERT Class 11, Ch 16.", stars: 5 },
  { id: 55, subject: "Biology", section: "Zoology", q: "Urea is synthesized in the human body in the:", options: ["Kidney", "Liver", "Spleen", "Pancreas"], ans: 1, exp: "Ornithine cycle (Krebs-Henseleit urea cycle): occurs in LIVER. NH₃ + CO₂ → citrulline → argininosuccinate → arginine → urea + ornithine. Urea is then transported to kidneys for excretion in urine. Ammonia is toxic; urea is less toxic and water-soluble. NCERT Class 11, Ch 19.", stars: 4 },
  { id: 56, subject: "Biology", section: "Zoology", q: "The wave of contraction that moves food down the oesophagus is called:", options: ["Segmentation", "Peristalsis", "Mastication", "Deglutition"], ans: 1, exp: "Peristalsis: wave-like muscular contractions of GI tract wall (circular and longitudinal muscles). Moves food bolus from oesophagus through GI tract. Segmentation: rhythmic contractions of small intestine that mix food with digestive juices (no net forward movement). NCERT Class 11, Ch 16.", stars: 4 },
  { id: 57, subject: "Biology", section: "Zoology", q: "The pacemaker of the heart is:", options: ["AV node", "Bundle of His", "SA node (sinoatrial node)", "Purkinje fibres"], ans: 2, exp: "SA node: located in right atrium wall; generates electrical impulse at ~72 beats/min → AV node (delay 0.1s) → Bundle of His → Purkinje fibres → ventricles. ECG waves: P (atrial depolarization), QRS (ventricular depolarization), T (ventricular repolarization). NCERT Class 11, Ch 18.", stars: 5 },
  { id: 58, subject: "Biology", section: "Zoology", q: "Sickle-cell anaemia is caused by:", options: ["Deletion of one amino acid in beta-globin", "Substitution of Glutamic acid (Glu) by Valine (Val) at position 6 of beta-globin", "Point mutation in alpha-globin", "Frameshift mutation in haemoglobin gene"], ans: 1, exp: "Sickle-cell anaemia: autosomal recessive. Mutation: GAG (Glu) → GTG (Val) — missense mutation. Valine is non-polar, causes HbS to polymerize under low O₂ → sickle-shaped RBCs → haemolysis, anaemia, vascular blockage. Heterozygotes (HbAHbS) are protected from malaria. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 59, subject: "Biology", section: "Zoology", q: "Which part of the nephron is impermeable to water but permeable to ions (Na⁺)?", options: ["PCT", "Descending limb of Loop of Henle", "Ascending limb of Loop of Henle", "Collecting duct"], ans: 2, exp: "Counter-current mechanism in nephron: Ascending limb of Loop of Henle is impermeable to water but actively transports Na⁺ and Cl⁻ out (creates hypertonic medullary interstitium). Descending limb is permeable to water (passive). This concentrates urine. NCERT Class 11, Ch 19.", stars: 5 },
  { id: 60, subject: "Biology", section: "Zoology", q: "Oogamy refers to fertilization between:", options: ["Two equal-sized motile gametes", "A large non-motile egg and a small motile sperm", "Two non-motile gametes", "Two equal non-motile gametes"], ans: 1, exp: "Types of sexual reproduction by gametes: Isogamy (both gametes equal, motile, e.g., Cladophora), Anisogamy (gametes unequal in size, both motile, e.g., Volvox), Oogamy (highly differentiated — large non-motile egg + small motile sperm, e.g., all mammals, Fucus). NCERT Class 12, Ch 1.", stars: 4 },
  { id: 61, subject: "Biology", section: "Zoology", q: "Which type of RNA carries amino acids to the ribosome during translation?", options: ["mRNA", "rRNA", "tRNA (transfer RNA)", "hnRNA"], ans: 2, exp: "tRNA = adaptor molecule (as proposed by Crick). Has anticodon loop (3-letter anticodon complementary to mRNA codon) and amino acid attachment site (3'-CCA-OH end). Aminoacyl-tRNA synthetase charges tRNA with correct amino acid. NCERT Class 12, Ch 6.", stars: 5 },
  { id: 62, subject: "Biology", section: "Zoology", q: "The process of obtaining the complete genome sequence is called:", options: ["PCR", "Recombinant DNA technology", "Genome sequencing / genomics", "Gene cloning"], ans: 2, exp: "Human Genome Project (HGP, 1990–2003): international collaboration. Goals: sequence all 3.2 billion base pairs of human genome, map all genes (~20,000–25,000 genes). Methods: BAC cloning + shotgun sequencing + bioinformatics. Used Celera Genomics (J.C. Venter) for private sequencing. NCERT Class 12, Ch 6.", stars: 4 },
  { id: 63, subject: "Biology", section: "Zoology", q: "Vaccine development from Bt toxin gene involves which type of organism?", options: ["Bacillus thuringiensis (soil bacterium)", "Agrobacterium tumefaciens", "E. coli", "Rhizobium"], ans: 0, exp: "Bt toxin: encoded by cry genes in Bacillus thuringiensis. Bt cotton has cry1Ac and cry2Ab genes (protects from bollworm). Bt brinjal has cry1Ac gene. The protein is protoxin (inactive) — activated in alkaline insect midgut → forms pores → cell lysis → insect death. NCERT Class 12, Ch 12.", stars: 4 },
  { id: 64, subject: "Biology", section: "Zoology", q: "HIV (Human Immunodeficiency Virus) primarily infects:", options: ["T-helper cells (CD4⁺ cells)", "B-lymphocytes", "RBCs", "Neutrophils"], ans: 0, exp: "HIV is a retrovirus. Envelope protein gp120 binds to CD4 receptor on T-helper cells. Reverse transcriptase converts viral RNA → DNA → integrates into host DNA (provirus). Kills T-helper cells → immune deficiency → opportunistic infections → AIDS. Window period: 8–10 years average. NCERT Class 12, Ch 8.", stars: 5 },
  { id: 65, subject: "Biology", section: "Zoology", q: "In population ecology, 'K' in the logistic growth equation represents:", options: ["Rate of increase", "Carrying capacity of the environment", "Initial population size", "Population at time t"], ans: 1, exp: "Logistic growth: dN/dt = rN(K-N)/K. K = carrying capacity = maximum population size the environment can sustainably support. When N=K, dN/dt=0 (population stable). Sigmoidal (S-shaped) growth. Real populations show logistic growth due to resource limitation. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 66, subject: "Biology", section: "Zoology", q: "Miller and Urey's experiment (1953) simulated early Earth conditions to demonstrate:", options: ["Origin of cells", "Chemical evolution — formation of amino acids from inorganic compounds", "Natural selection", "Origin of photosynthesis"], ans: 1, exp: "Miller-Urey experiment: electric discharge through CH₄, H₂, NH₃, H₂O (reducing atmosphere) → simple amino acids, organic acids. Supported Oparin-Haldane hypothesis of chemical origin of life. NCERT Class 12, Ch 7.", stars: 4 },
  { id: 67, subject: "Biology", section: "Zoology", q: "Adaptive radiation refers to:", options: ["Radiation from radioactive isotopes causing mutations", "Evolution of many diverse species from a common ancestor in a new environment", "Migration of populations due to radiation stress", "Parallel evolution in different continents"], ans: 1, exp: "Adaptive radiation: Darwin's finches in Galapagos Islands (14 species from 1 ancestor) — best example. Also: marsupials in Australia, placental mammals globally. Divergent evolution from common ancestor. NCERT Class 12, Ch 7.", stars: 4 },
  { id: 68, subject: "Biology", section: "Zoology", q: "Hardy-Weinberg principle states that allele frequencies in a population remain constant if:", options: ["Natural selection acts", "Large random-mating population with no mutation, migration, selection, genetic drift", "Population is small", "Genetic drift occurs"], ans: 1, exp: "Hardy-Weinberg law: p² + 2pq + q² = 1, where p = freq of dominant allele, q = recessive allele. Conditions: (1) Random mating, (2) No mutation, (3) No migration, (4) No selection, (5) Large population size. Any deviation = evolution occurring. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 69, subject: "Biology", section: "Zoology", q: "El Nino phenomenon affects which major biogeochemical cycle?", options: ["Carbon cycle", "Sulphur cycle", "Nitrogen cycle", "Water/hydrological cycle"], ans: 0, exp: "El Niño (ENSO): warming of Pacific Ocean surface → affects global precipitation and temperature patterns → drought in some regions → impacts forest fires, ocean productivity → disrupts carbon cycle (more CO₂ from fires, less oceanic uptake). NCERT Class 12, Ch 14.", stars: 4 },
  { id: 70, subject: "Biology", section: "Zoology", q: "Which of the following is a PRIMARY air pollutant directly emitted from source?", options: ["Ozone (O₃)", "Sulphur dioxide (SO₂)", "PAN (Peroxyacetyl nitrate)", "Acid rain"], ans: 1, exp: "Primary pollutants: directly emitted — SO₂, NO, CO, SPM, hydrocarbons, CO₂. Secondary pollutants: formed by reaction of primary pollutants in atmosphere — O₃, PAN, acid rain (H₂SO₄, HNO₃), smog. NCERT Class 12, Ch 16.", stars: 4 },
  { id: 71, subject: "Biology", section: "Zoology", q: "The dodo bird became extinct due to:", options: ["Natural selection", "Over-exploitation and habitat destruction by humans", "Climate change", "Disease"], ans: 1, exp: "Dodo (Raphus cucullatus) of Mauritius — flightless bird extinct by ~1680 due to hunting by sailors and introduction of invasive species (pigs, dogs, cats) by humans. Sixth mass extinction is ongoing (human-caused). IUCN Red List categories: Extinct, Critically Endangered, Endangered, Vulnerable. NCERT Class 12, Ch 15.", stars: 4 },
  { id: 72, subject: "Biology", section: "Zoology", q: "In which phase of meiosis does 'crossing over' occur?", options: ["Leptotene", "Zygotene", "Pachytene", "Diplotene"], ans: 2, exp: "Meiosis I Prophase sub-stages: Leptotene (chromosome condensation), Zygotene (synapsis begins, bivalent/synaptonemal complex forms), Pachytene (crossing over occurs — exchange of chromatid segments at chiasmata), Diplotene (chiasmata visible, chromosomes repel), Diakinesis (chiasmata terminalization). NCERT Class 11, Ch 10.", stars: 4 },
  { id: 73, subject: "Biology", section: "Zoology", q: "Restriction fragment length polymorphism (RFLP) is useful in:", options: ["DNA amplification", "DNA fingerprinting / forensic identification", "Protein synthesis", "Gene expression analysis only"], ans: 1, exp: "DNA fingerprinting (Alec Jeffreys, 1985): uses RFLP (restriction enzymes cut DNA at specific sites) and VNTRs (variable number tandem repeats). Southern blotting + probe hybridization → DNA profile. Used in: forensics, paternity testing, criminal identification, identifying disaster victims. NCERT Class 12, Ch 6.", stars: 4 },
  { id: 74, subject: "Biology", section: "Zoology", q: "Agrobacterium tumefaciens is used in plant genetic engineering because it:", options: ["Produces insecticides", "Is a natural genetic engineer — its Ti plasmid can insert DNA into plant cells", "Fixes nitrogen", "Produces plant hormones"], ans: 1, exp: "Agrobacterium tumefaciens: soil bacterium causing crown gall disease. Contains Ti (tumour-inducing) plasmid which integrates T-DNA into plant nuclear genome. Used as a vector to introduce desired genes into plants. Disarmed Ti plasmid (T-DNA genes removed) is used in plant transformation. NCERT Class 12, Ch 11.", stars: 4 },
  { id: 75, subject: "Biology", section: "Zoology", q: "In PCR, the enzyme that can withstand high temperature (94°C) is:", options: ["E. coli DNA polymerase I", "Taq polymerase (from Thermus aquaticus)", "Reverse transcriptase", "Ligase"], ans: 1, exp: "PCR uses Taq polymerase (thermostable DNA polymerase from Thermus aquaticus, a thermophilic bacterium). Heat-stable up to 95°C. PCR steps (per cycle): 94°C (denaturation) → 54°C (annealing of primers) → 72°C (extension by Taq polymerase). Exponential amplification: n cycles → 2ⁿ copies. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 76, subject: "Biology", section: "Zoology", q: "Biodiversity loss is LEAST likely to be caused by:", options: ["Habitat destruction", "Over-exploitation", "Captive breeding programs", "Introduction of invasive species"], ans: 2, exp: "Causes of biodiversity loss (HIPPO): Habitat destruction, Invasive species, Pollution, Population growth, Over-exploitation. Captive breeding programmes (ex situ conservation) in zoos and breeding centres CONSERVE biodiversity, not destroy it. NCERT Class 12, Ch 15.", stars: 4 },
  { id: 77, subject: "Biology", section: "Zoology", q: "The organ that produces bile and converts ammonia to urea is:", options: ["Pancreas", "Kidney", "Liver", "Gallbladder"], ans: 2, exp: "Liver functions: (1) Bile production (emulsification of fats, stored in gallbladder), (2) Urea synthesis (detoxification of ammonia), (3) Glycogen storage, (4) Plasma protein synthesis (albumin, fibrinogen), (5) Cholesterol synthesis, (6) Vitamin storage (A, D, B12), (7) Detoxification of drugs. NCERT Class 11, Ch 16.", stars: 4 },
  { id: 78, subject: "Biology", section: "Zoology", q: "Which immunoglobulin (Ig) is present in colostrum (first milk) and provides passive immunity to newborns?", options: ["IgM", "IgD", "IgA", "IgE"], ans: 2, exp: "IgA: found in secretions — colostrum, saliva, tears, breast milk, mucus. Provides passive immunity to newborn (gut). IgM: first antibody produced in primary immune response; pentameric. IgG: most abundant in blood, crosses placenta. IgE: involved in allergic reactions (binds mast cells). NCERT Class 12, Ch 8.", stars: 4 },
  { id: 79, subject: "Biology", section: "Zoology", q: "Which hormone triggers ovulation in females?", options: ["FSH", "LH surge", "Progesterone", "Oestrogen alone"], ans: 1, exp: "Ovulation: LH surge (peak of LH around day 14) triggers rupture of Graafian follicle → release of secondary oocyte. FSH stimulates follicle development and oestrogen secretion. Positive feedback: rising oestrogen → triggers LH surge → ovulation. Ovulation at ~day 14 of 28-day cycle. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 80, subject: "Biology", section: "Zoology", q: "The process by which mRNA is made from DNA template is called:", options: ["Translation", "Replication", "Transcription", "Reverse transcription"], ans: 2, exp: "Transcription: DNA → mRNA, catalysed by RNA polymerase. Template strand (antisense/non-coding) read 3'→5', mRNA synthesised 5'→3'. In eukaryotes: hnRNA (pre-mRNA) → capping, polyadenylation, splicing (introns removed) → mature mRNA → exported to cytoplasm. NCERT Class 12, Ch 6.", stars: 4 },
  { id: 81, subject: "Biology", section: "Zoology", q: "Down's syndrome is caused by trisomy of chromosome:", options: ["13", "18", "21", "23"], ans: 2, exp: "Down's syndrome (Trisomy 21): 47 chromosomes, extra chromosome 21 (most common cause = non-disjunction during meiosis in mother). Features: broad forehead, epicanthic fold, short stature, intellectual disability, single palmar crease, increased risk of heart defects. NCERT Class 12, Ch 5.", stars: 5 },
  { id: 82, subject: "Biology", section: "Zoology", q: "The fluid part of blood (without cells and clotting factors) is called:", options: ["Plasma", "Serum", "Lymph", "Interstitial fluid"], ans: 1, exp: "Blood = Plasma + Blood cells (RBCs, WBCs, platelets). Plasma = fluid + proteins (fibrinogen, albumin, globulins). Serum = Plasma − clotting factors (fibrinogen removed after clotting). Lymph = filtered interstitial fluid; similar to plasma but less protein. NCERT Class 11, Ch 18.", stars: 4 },
  { id: 83, subject: "Biology", section: "Zoology", q: "Parkinson's disease is caused by degeneration of neurons producing:", options: ["Acetylcholine", "Dopamine", "Serotonin", "GABA"], ans: 1, exp: "Parkinson's disease: degeneration of dopaminergic neurons in substantia nigra of basal ganglia. Dopamine deficiency → tremors, rigidity, bradykinesia. Treatment: L-DOPA (precursor to dopamine). Alzheimer's: loss of acetylcholine neurons + beta-amyloid plaques. NCERT Class 11, Ch 21.", stars: 4 },
  { id: 84, subject: "Biology", section: "Zoology", q: "Which type of RNA forms the structural and functional backbone of ribosomes?", options: ["mRNA", "tRNA", "rRNA (ribosomal RNA)", "snRNA"], ans: 2, exp: "Ribosomes: 80S (eukaryotes) = 60S + 40S subunits; 70S (prokaryotes) = 50S + 30S. rRNA + ribosomal proteins = ribosome. rRNA is the most abundant RNA (~80% of total RNA). rRNA has enzymatic activity (peptidyl transferase = ribozyme). NCERT Class 11, Ch 8.", stars: 4 },
  { id: 85, subject: "Biology", section: "Zoology", q: "The Eustachian tube connects the:", options: ["Pharynx to the middle ear", "Outer ear to inner ear", "Middle ear to inner ear", "Nasal cavity to throat"], ans: 0, exp: "Eustachian tube: connects middle ear cavity to pharynx (nasopharynx). Function: equalizes air pressure on both sides of eardrum (tympanic membrane). Blockage → painful pressure difference (during flight, cold). NCERT Class 11, Ch 21.", stars: 4 },
  { id: 86, subject: "Biology", section: "Zoology", q: "Which is the LARGEST WHITE BLOOD CELL (WBC)?", options: ["Neutrophil", "Lymphocyte", "Basophil", "Monocyte"], ans: 3, exp: "WBCs (Leucocytes): Granulocytes — Neutrophils (60–65%, phagocytic), Eosinophils (2–3%, allergy/parasite), Basophils (<1%, histamine/heparin). Agranulocytes — Lymphocytes (20–25%, immunity) and Monocytes (6–8%, LARGEST WBC, differentiate into macrophages). NCERT Class 11, Ch 18.", stars: 4 },
  { id: 87, subject: "Biology", section: "Zoology", q: "The reflex arc pathway is:", options: ["Receptor → Afferent nerve → Effector → Efferent nerve → Response", "Receptor → Afferent nerve → Spinal cord (nerve centre) → Efferent nerve → Effector → Response", "Effector → Efferent nerve → Receptor", "Brain → Spinal cord → Effector"], ans: 1, exp: "Reflex arc: Receptor → Afferent (sensory) nerve → Nerve centre (spinal cord or brain) → Efferent (motor) nerve → Effector (muscle/gland). Reflex action is involuntary, fast, stereotyped response. Knee-jerk reflex = monosynaptic. NCERT Class 11, Ch 21.", stars: 4 },
  { id: 88, subject: "Biology", section: "Zoology", q: "Which vitamin is synthesized by bacteria in the human intestine?", options: ["Vitamin A", "Vitamin C", "Vitamin K", "Vitamin E"], ans: 2, exp: "Vitamin K (phylloquinone/menaquinone): fat-soluble vitamin. Synthesized by intestinal bacteria (E. coli). Essential for blood clotting (activates factors II, VII, IX, X). Deficiency → bleeding disorder. Newborns receive Vitamin K injection as gut is sterile initially. NCERT Class 11, Ch 16.", stars: 4 },
  { id: 89, subject: "Biology", section: "Zoology", q: "Thyroid stimulating hormone (TSH) is secreted by:", options: ["Thyroid gland", "Anterior pituitary (adenohypophysis)", "Hypothalamus", "Posterior pituitary"], ans: 1, exp: "Anterior pituitary hormones: GH, TSH, ACTH, FSH, LH, Prolactin. TSH stimulates thyroid to secrete T₃ and T₄. Hypothalamus releases TRH (thyrotropin-releasing hormone) → triggers TSH. Negative feedback: high T₃/T₄ → inhibit TSH/TRH. NCERT Class 11, Ch 22.", stars: 5 },
  { id: 90, subject: "Biology", section: "Zoology", q: "The protective layer that covers the organs of the thoracic and abdominal cavities is called:", options: ["Pleura", "Peritoneum", "Pericardium", "Meninges"], ans: 1, exp: "Peritoneum: serous membrane lining the abdominal cavity and covering abdominal organs. Pleura: lines the thoracic cavity and covers lungs. Pericardium: double-walled sac around heart. Meninges: three layers (dura, arachnoid, pia mater) protecting brain and spinal cord. NCERT Class 11, anatomy.", stars: 4 },

  // CHEMISTRY (91-135)
  { id: 91, subject: "Chemistry", section: "Physical Chemistry", q: "For a first-order reaction, the half-life is:", options: ["Proportional to initial concentration", "t₁/₂ = 0.693/k (independent of initial concentration)", "t₁/₂ = [A]₀/2k", "t₁/₂ = 1/k[A]₀"], ans: 1, exp: "First-order: rate = k[A]. t₁/₂ = 0.693/k. Independent of [A]₀. Zero-order: t₁/₂ = [A]₀/2k. Second-order: t₁/₂ = 1/k[A]₀. Radioactive decay follows first-order. Unit of first-order k: s⁻¹. NCERT Class 12, Ch 4.", stars: 5 },
  { id: 92, subject: "Chemistry", section: "Physical Chemistry", q: "Which of the following is the correct statement about ΔG for a spontaneous reaction?", options: ["ΔG > 0", "ΔG = 0", "ΔG < 0", "ΔG depends on temperature only"], ans: 2, exp: "ΔG = ΔH − TΔS. For spontaneous: ΔG < 0. At equilibrium: ΔG = 0. ΔG° = −RT ln K. If K >> 1, ΔG° << 0 (spontaneous). Temperature determines whether endothermic reactions become spontaneous (if TΔS > ΔH). NCERT Class 11, Ch 6.", stars: 5 },
  { id: 93, subject: "Chemistry", section: "Inorganic Chemistry", q: "Hybridization and shape of XeF₄ is:", options: ["sp³d, see-saw", "sp³d², square planar", "sp³, tetrahedral", "sp³d², octahedral"], ans: 1, exp: "XeF₄: 4 bond pairs + 2 lone pairs → sp³d² hybridisation → octahedral electron geometry → square planar molecular geometry (lone pairs occupy axial positions). Bond angle 90°. XeF₂: sp³d, linear. NCERT Class 12, Ch 7.", stars: 5 },
  { id: 94, subject: "Chemistry", section: "Inorganic Chemistry", q: "In coordination chemistry, the CFSE (Crystal Field Stabilization Energy) is greatest for:", options: ["Weak field ligands", "Strong field ligands", "Tetrahedral complexes", "All ligands equally"], ans: 1, exp: "Spectrochemical series (weak → strong): I⁻ < Br⁻ < Cl⁻ < F⁻ < OH⁻ < H₂O < NH₃ < en < CN⁻ < CO. Strong field ligands cause large crystal field splitting (Δo), CFSE is large. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 95, subject: "Chemistry", section: "Organic Chemistry", q: "The iodoform test is POSITIVE for which of the following?", options: ["Methanol", "Propan-1-ol", "Propan-2-ol", "Pentan-3-ol"], ans: 2, exp: "Iodoform test (positive for CH₃CO- group or oxidizable to it): CH₃CHO, CH₃COCH₃, C₂H₅OH, CH₃CHOH-R. Propan-2-ol = CH₃CHOH-CH₃ (has CH₃CHOH group → positive). Propan-1-ol (CH₃CH₂CH₂OH) → negative. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 96, subject: "Chemistry", section: "Inorganic Chemistry", q: "The Haber process for industrial synthesis of ammonia requires:", options: ["High temperature, low pressure, Fe catalyst", "Moderate temperature (400-500°C), high pressure (200 atm), Fe/Mo catalyst", "Low temperature, low pressure", "High temperature, high pressure, Pt catalyst"], ans: 1, exp: "Haber process: N₂ + 3H₂ ⇌ 2NH₃ (ΔH = −92 kJ/mol, exothermic). Compromise conditions: 400–500°C (kinetics), 200 atm (Le Chatelier — fewer moles of gas on product side), iron catalyst with Mo promoter. NCERT Class 12, Ch 7.", stars: 4 },
  { id: 97, subject: "Chemistry", section: "Organic Chemistry", q: "Benzoic acid can be separated from a mixture with naphthalene by:", options: ["Extraction with ether", "Addition of NaHCO₃ solution (benzoic acid dissolves, naphthalene does not)", "Distillation", "Chromatography only"], ans: 1, exp: "Benzoic acid (pKa = 4.2) reacts with NaHCO₃: C₆H₅COOH + NaHCO₃ → C₆H₅COONa + H₂O + CO₂. Aqueous layer contains sodium benzoate; organic layer contains naphthalene. Phenol does NOT react with NaHCO₃ (pKa=10) but reacts with NaOH. NCERT Class 12, Ch 11.", stars: 4 },
  { id: 98, subject: "Chemistry", section: "Organic Chemistry", q: "Which of the following undergoes nucleophilic substitution (SN2) most readily?", options: ["(CH₃)₃CBr", "(CH₃)₂CHBr", "CH₃CH₂Br", "CH₃Br"], ans: 3, exp: "SN2: Rate = k[substrate][nucleophile]. Bimolecular. Favoured by less steric hindrance. Order of reactivity: CH₃X > 1°X > 2°X > 3°X. CH₃Br (methyl bromide, no alkyl groups) is MOST reactive in SN2. Inversion of configuration (Walden inversion). NCERT Class 12, Ch 10.", stars: 4 },
  { id: 99, subject: "Chemistry", section: "Physical Chemistry", q: "Nernst equation for an electrochemical cell is:", options: ["E = E° + (RT/nF) ln Q", "E = E° − (RT/nF) ln Q", "E = RT/nF × ln Q", "E = −RT/nF × ln Q"], ans: 1, exp: "Nernst equation: E = E° − (RT/nF) ln Q = E° − (0.0591/n) log Q at 298K. At equilibrium: E=0, Q=K → ΔG° = −nFE° = −RT ln K. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 100, subject: "Chemistry", section: "Organic Chemistry", q: "Electrophilic aromatic substitution (EAS) is FASTEST in which compound?", options: ["Benzene", "Chlorobenzene", "Nitrobenzene", "Aniline (PhNH₂)"], ans: 3, exp: "EAS reactivity: −NH₂ > −OH > −OCH₃ > −CH₃ >> Benzene >> −Cl > −Br >> −NO₂ >> −CN. −NH₂ is a strong activating ortho/para director (lone pair donation into ring increases electron density). −NO₂ is strongly deactivating meta director. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 101, subject: "Chemistry", section: "Physical Chemistry", q: "Boiling point elevation (ΔTb) is a colligative property. It depends on:", options: ["Nature of solute", "Mass of solvent only", "Number of solute particles (molality of solution)", "Pressure"], ans: 2, exp: "Colligative properties depend on NUMBER of solute particles, NOT their nature: (1) Relative lowering of vapour pressure, (2) Elevation of boiling point (ΔTb = Kb×m), (3) Depression of freezing point (ΔTf = Kf×m), (4) Osmotic pressure (π = MRT). NCERT Class 12, Ch 2.", stars: 5 },
  { id: 102, subject: "Chemistry", section: "Organic Chemistry", q: "Which reagent is used to distinguish between aldehydes and ketones?", options: ["Fehling's solution (positive for aldehydes only)", "Iodoform reagent", "Lucas reagent", "Grignard reagent"], ans: 0, exp: "Fehling's test: alkaline copper(II) tartrate solution (deep blue) → reduced by aldehydes (RCHO) to Cu₂O (brick-red ppt). Ketones do NOT reduce Fehling's. Tollens' reagent (ammoniacal AgNO₃) → silver mirror with aldehydes. NCERT Class 12, Ch 12.", stars: 5 },
  { id: 103, subject: "Chemistry", section: "Organic Chemistry", q: "The IUPAC name of the compound CH₂=CH-CH₂-OH is:", options: ["Allyl alcohol", "2-propen-1-ol", "Propenol", "3-hydroxy-1-propene"], ans: 1, exp: "CH₂=CH-CH₂-OH: 3 carbons, double bond at C1-C2, OH at C1. IUPAC: parent = prop-2-en-1-ol (or 2-propen-1-ol). Common name: allyl alcohol. NCERT Class 12, Ch 11.", stars: 4 },
  { id: 104, subject: "Chemistry", section: "Inorganic Chemistry", q: "Which of the following has the highest lattice energy?", options: ["NaCl", "MgO", "NaF", "KCl"], ans: 1, exp: "Lattice energy ∝ (charge of ions)/(interionic distance). MgO: Mg²⁺ and O²⁻ → charge product = 2×2 = 4. NaCl: Na⁺ and Cl⁻ → charge product = 1×1 = 1. Higher charge → stronger ionic attraction → higher lattice energy. MgO (3795 kJ/mol) >> NaCl (787 kJ/mol). NCERT Class 11, Ch 4.", stars: 4 },
  { id: 105, subject: "Chemistry", section: "Organic Chemistry", q: "In Sandmeyer's reaction, diazonium salt is converted to:", options: ["Phenol", "Aniline", "Aryl halide (Ar-Cl or Ar-Br) using CuCl/CuBr", "Azo compound"], ans: 2, exp: "Sandmeyer's reaction: ArN₂⁺ + CuCl → Ar-Cl + N₂ (or CuBr → Ar-Br). Gattermann's reaction: uses Cu powder + HCl/HBr. Diazonium → phenol (warm water, H₂SO₄), → ArF (Balz-Schiemann, HBF₄), → ArCN (CuCN), → azo dye (coupling with phenol/amine). NCERT Class 12, Ch 13.", stars: 4 },
  { id: 106, subject: "Chemistry", section: "Physical Chemistry", q: "The van't Hoff factor (i) for Na₂SO₄ in dilute aqueous solution is:", options: ["1", "2", "3", "4"], ans: 2, exp: "Na₂SO₄ → 2Na⁺ + SO₄²⁻ (3 ions). Van't Hoff factor i = number of particles after dissociation/number before. For i > 1: dissociation; i < 1: association. ΔTb = i × Kb × m. For NaCl: i = 2. For AlCl₃: i = 4. For sucrose: i = 1 (no dissociation). NCERT Class 12, Ch 2.", stars: 4 },
  { id: 107, subject: "Chemistry", section: "Organic Chemistry", q: "Which compound does NOT show optical isomerism?", options: ["Lactic acid", "Alanine", "2-chlorobutane", "2-chloro-2-methylpropane (t-butyl chloride)"], ans: 3, exp: "Optical isomerism requires a chiral centre (4 different groups). 2-chloro-2-methylpropane: C has 3 identical CH₃ groups → NOT chiral. Lactic acid (CH₃CHOHCOOH), Alanine (CH₃CHNH₂COOH), 2-chlorobutane (CH₃CHClCH₂CH₃) all have chiral C with 4 different groups. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 108, subject: "Chemistry", section: "Physical Chemistry", q: "In a galvanic cell (Daniel cell), oxidation occurs at:", options: ["Cathode", "Anode", "Both electrodes", "Neither electrode"], ans: 1, exp: "Electrochemical cell: Anode = oxidation (OA), Cathode = reduction (RC). Mnemonic: OILRIG (Oxidation Is Loss, Reduction Is Gain). Daniel cell: Zn anode (Zn → Zn²⁺ + 2e⁻) | salt bridge | Cu cathode (Cu²⁺ + 2e⁻ → Cu). EMF = E°cathode − E°anode = 0.34 − (−0.76) = 1.10 V. NCERT Class 12, Ch 3.", stars: 5 },
  { id: 109, subject: "Chemistry", section: "Organic Chemistry", q: "Which of the following is a polysaccharide used for energy storage in animals?", options: ["Starch", "Cellulose", "Glycogen", "Chitin"], ans: 2, exp: "Polysaccharides: Starch (plants, energy storage, α-glucose, amylose+amylopectin), Glycogen (animals/fungi, energy storage, α-glucose, more branched than amylopectin), Cellulose (plant cell wall, β-glucose, structural), Chitin (exoskeleton of insects, crustaceans). NCERT Class 12, Ch 14.", stars: 4 },
  { id: 110, subject: "Chemistry", section: "Physical Chemistry", q: "The osmotic pressure equation is:", options: ["π = nRT/V", "π = MRT", "π = MRT where M = molarity", "Both B and C (same thing)"], ans: 3, exp: "Osmotic pressure: π = MRT (Van't Hoff equation), where M = molarity (mol/L), R = gas constant, T = temperature in Kelvin. For electrolytes: π = iMRT. Osmotic pressure can be used to determine molecular mass of large molecules (polymers, proteins) — very sensitive to small changes. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 111, subject: "Chemistry", section: "Organic Chemistry", q: "Which of the following is an example of nucleophilic addition?", options: ["Bromination of benzene", "Chlorination of methane (CH₄)", "Addition of HCN to acetaldehyde", "Nitration of benzene"], ans: 2, exp: "Nucleophilic addition: Nu⁻ attacks electrophilic carbonyl carbon (C=O). HCN → CN⁻ attacks carbonyl carbon → cyanohydrin. Other examples: addition of NaHSO₃, Grignard reagent, LiAlH₄ to carbonyl compounds. Bromination/nitration of benzene = electrophilic aromatic substitution. NCERT Class 12, Ch 12.", stars: 4 },
  { id: 112, subject: "Chemistry", section: "Inorganic Chemistry", q: "Coordination number of Cr in [Cr(NH₃)₄Cl₂]⁺ is:", options: ["4", "6", "5", "2"], ans: 1, exp: "[Cr(NH₃)₄Cl₂]⁺: 4 NH₃ + 2 Cl⁻ = 6 ligands around Cr → coordination number = 6. NH₃ = monodentate, neutral. Cl⁻ = monodentate, anionic. Cr has oxidation state +3 (4×0 + 2×(-1) + x = +1 → x=+3). Geometry = octahedral. Two geometrical isomers: cis and trans. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 113, subject: "Chemistry", section: "Organic Chemistry", q: "Phenol reacts with Na metal to give:", options: ["Sodium phenate + H₂ gas", "Sodium phenate only", "No reaction", "Cyclohexanol"], ans: 0, exp: "Phenol + Na → Sodium phenate (C₆H₅ONa) + ½H₂. Phenol is acidic (pKa~10) due to resonance stabilization of phenoxide ion. More acidic than alcohols (pKa~16) but less acidic than carboxylic acids (pKa~5). Phenol does NOT react with NaHCO₃. NCERT Class 12, Ch 11.", stars: 4 },
  { id: 114, subject: "Chemistry", section: "Organic Chemistry", q: "Which is the correct order of acidic strength of carboxylic acids?", options: ["Acetic > Formic > Chloroacetic", "Formic > Acetic > Chloroacetic", "Chloroacetic > Formic > Acetic", "Formic > Chloroacetic > Acetic"], ans: 2, exp: "Acidic strength of carboxylic acids: electron-withdrawing groups (Cl, F, NO₂) increase acidity; electron-donating groups (CH₃, C₂H₅) decrease acidity. Chloroacetic (pKa 2.86) > Formic (pKa 3.75) > Acetic (pKa 4.74). NCERT Class 12, Ch 12.", stars: 4 },
  { id: 115, subject: "Chemistry", section: "Inorganic Chemistry", q: "In the Contact process for manufacturing H₂SO₄, the catalyst used is:", options: ["Iron oxide", "Platinum or V₂O₅ (vanadium pentoxide)", "Nickel", "Manganese dioxide"], ans: 1, exp: "Contact process: 2SO₂ + O₂ → 2SO₃ (catalyst: V₂O₅ at 450°C/1-2 atm). SO₃ + H₂SO₄ → oleum (H₂S₂O₇) → diluted with water → H₂SO₄. V₂O₅ is economically better than Pt (cheaper, resistant to poisoning). NCERT Class 12, Ch 7.", stars: 4 },
  { id: 116, subject: "Chemistry", section: "Organic Chemistry", q: "Wurtz reaction is used to prepare:", options: ["Aldehydes from alcohols", "Higher alkanes from alkyl halides using Na metal", "Alkyl halides from alkanes", "Alcohols from carboxylic acids"], ans: 1, exp: "Wurtz reaction: 2R-X + 2Na → R-R + 2NaX (in dry ether). Used to synthesize symmetrical alkanes (e.g., 2CH₃Br + 2Na → CH₃CH₃). Limitation: mixtures if two different alkyl halides used (Wurtz-Fittig for arene). NCERT Class 11, Ch 13.", stars: 4 },
  { id: 117, subject: "Chemistry", section: "Organic Chemistry", q: "Which of the following is an anti-Markovnikov addition?", options: ["HBr addition to propene without peroxide", "HCl addition to propene", "HBr addition to propene in presence of peroxide (radical mechanism)", "H₂O addition to propene"], ans: 2, exp: "Anti-Markovnikov addition (Kharasch effect): HBr adds anti-Markovnikov in presence of peroxides (radical mechanism). Br• attacks the less substituted carbon (exothermic step). This reversal is specific to HBr only (NOT HCl or HI — due to bond energies). NCERT Class 11, Ch 13.", stars: 4 },
  { id: 118, subject: "Chemistry", section: "Physical Chemistry", q: "Chromatography is based on the principle of:", options: ["Difference in solubility only", "Differential adsorption/distribution between stationary and mobile phases", "Difference in boiling point", "Magnetic properties"], ans: 1, exp: "Chromatography: separation based on differential distribution between stationary phase and mobile phase. Types: Column chromatography (adsorption), TLC, Paper chromatography (partition), Gas chromatography (vapour pressure), HPLC. Rf = distance moved by solute / distance moved by solvent. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 119, subject: "Chemistry", section: "Organic Chemistry", q: "Which of the following is a bio-degradable polymer?", options: ["Polythene", "Nylon-6,6", "PHBV (polyhydroxybutyrate-co-hydroxyvalerate)", "Bakelite"], ans: 2, exp: "PHBV: biodegradable polyester produced by bacteria (Ralstonia eutropha). Degrades in soil by microbes. Used in surgical sutures, disposable packaging. Other biodegradable polymers: poly(lactic acid) — PLA, Nylon-2-nylon-6 (polyamide). Polythene, nylon-6,6, bakelite are non-biodegradable. NCERT Class 12, Ch 15.", stars: 4 },
  { id: 120, subject: "Chemistry", section: "Physical Chemistry", q: "The buffer solution that maintains blood pH at approximately 7.4 primarily involves:", options: ["H₂CO₃/NaHCO₃ buffer system", "H₃PO₄/NaH₂PO₄ buffer", "NaCl/NaOH", "Na₂CO₃/NaHCO₃"], ans: 0, exp: "Blood pH 7.4 maintained by: (1) H₂CO₃/HCO₃⁻ buffer (major), (2) Phosphate buffer (intracellular), (3) Protein buffer (haemoglobin). Henderson-Hasselbalch: pH = pKa + log([HCO₃⁻]/[H₂CO₃]). Ratio [HCO₃⁻]/[H₂CO₃] ≈ 20:1 at pH 7.4. NCERT Class 11, Ch 7.", stars: 4 },
  { id: 121, subject: "Chemistry", section: "Inorganic Chemistry", q: "d-block elements show variable oxidation states because:", options: ["Their s-subshell is filled last", "(n-1)d and ns electrons have similar energies and can both be used in bonding", "They have no d-electrons", "Only their p-electrons participate in bonding"], ans: 1, exp: "d-block (transition) elements: [Ar]3d¹⁻¹⁰4s¹⁻². Both 3d and 4s electrons are close in energy → both can be used in bond formation → variable oxidation states. Mn: +2 to +7 (widest range). NCERT Class 12, Ch 8.", stars: 4 },
  { id: 122, subject: "Chemistry", section: "Organic Chemistry", q: "The process of coupling a diazonium salt with phenol in alkaline medium gives:", options: ["Azo dye (orange-red coloured compound)", "Phenol", "Benzene", "Benzaldehyde"], ans: 0, exp: "Coupling reaction: ArN₂⁺ (diazonium) + phenol/amine → Ar-N=N-Ar' (azo compound, highly coloured). Para coupling preferred. Used in synthesis of azo dyes (textile industry). NCERT Class 12, Ch 13.", stars: 4 },
  { id: 123, subject: "Chemistry", section: "Organic Chemistry", q: "Which of the following is an example of a condensation polymer?", options: ["Polyethylene (polythene)", "Nylon-6,6", "Polystyrene", "Polyvinyl chloride (PVC)"], ans: 1, exp: "Condensation polymer: formed by condensation reaction (elimination of small molecule like H₂O). Nylon-6,6: hexamethylenediamine + adipic acid → [-NH-(CH₂)₆-NH-CO-(CH₂)₄-CO-]n + H₂O. Addition polymers (no small molecule lost): Polythene, PVC, polystyrene, Buna-S. NCERT Class 12, Ch 15.", stars: 4 },
  { id: 124, subject: "Chemistry", section: "Physical Chemistry", q: "In Le Chatelier's principle, if pressure is increased for N₂ + 3H₂ ⇌ 2NH₃, the equilibrium shifts:", options: ["To the left (more N₂ and H₂)", "To the right (more NH₃)", "No change", "Depends on temperature"], ans: 1, exp: "Le Chatelier: increasing pressure → equilibrium shifts to side with fewer moles of gas. Reactants: 1+3=4 mol gas; Products: 2 mol gas. ∴ Equilibrium shifts to right (more NH₃). This is why high pressure (200 atm) is used in Haber process. NCERT Class 11, Ch 7.", stars: 5 },
  { id: 125, subject: "Chemistry", section: "Organic Chemistry", q: "Amino acids are joined by which type of bond in proteins?", options: ["Hydrogen bond", "Peptide bond (amide bond)", "Disulfide bond", "Ionic bond"], ans: 1, exp: "Peptide bond: formed by condensation between -COOH of one amino acid and -NH₂ of next (loss of H₂O). -CO-NH- linkage. Primary structure = sequence of amino acids connected by peptide bonds. Secondary structure = H-bonds (α-helix, β-pleated sheet). NCERT Class 12, Ch 14.", stars: 5 },
  { id: 126, subject: "Chemistry", section: "Physical Chemistry", q: "Assertion: Methyl orange changes colour at pH 3.1 to 4.4. Reason: It is a weak acid indicator.", options: ["Both A and R true, R is correct explanation", "Both A and R true, R not correct explanation", "A is true, R is false", "A is false, R is true"], ans: 0, exp: "Methyl orange: indicator for acid range, changes pH 3.1 (red) to 4.4 (yellow). Phenolphthalein: 8.3–10 (colourless to pink, basic range). NCERT Class 11, Ch 7.", stars: 4 },
  { id: 127, subject: "Chemistry", section: "Organic Chemistry", q: "Which of the following is used as an antiseptic?", options: ["0.2% phenol solution", "5% phenol solution", "Concentrated H₂SO₄", "NaOH solution"], ans: 0, exp: "Dettol = chloroxylenol (antiseptic). Phenol 0.2% = antiseptic (for skin wounds). Phenol 1% = disinfectant (non-living surfaces). Chlorine (Cl₂) is used to disinfect drinking water (0.5 ppm). Iodoform (CHI₃) has antiseptic properties. NCERT Class 12, Ch 16.", stars: 4 },
  { id: 128, subject: "Chemistry", section: "Physical Chemistry", q: "The boiling point of water is higher than that of H₂S because:", options: ["Water has higher molecular weight", "Water molecules form extensive hydrogen bonding", "Water is a better solvent", "H₂S is more volatile"], ans: 1, exp: "H₂O: O is highly electronegative and small → forms strong H-bonds (O-H···O). Extensive intermolecular H-bonding raises boiling point to 100°C despite low MW (18 g/mol). H₂S: S is large, less electronegative → very weak H-bonds → bp = −60°C. NCERT Class 11, Ch 4.", stars: 4 },
  { id: 129, subject: "Chemistry", section: "Physical Chemistry", q: "In an aqueous solution, which ionizes completely (strong electrolyte)?", options: ["Acetic acid", "Ammonia", "Hydrochloric acid (HCl)", "Glucose"], ans: 2, exp: "Strong electrolytes (complete ionization): HCl, HBr, HI, HNO₃, H₂SO₄, HClO₄ (strong acids); NaOH, KOH, Ba(OH)₂ (strong bases); NaCl, KNO₃, etc. (salts). Weak electrolytes: CH₃COOH, NH₃, HF, H₂CO₃. Non-electrolytes: glucose, urea, ethanol. NCERT Class 11, Ch 7.", stars: 4 },
  { id: 130, subject: "Chemistry", section: "Organic Chemistry", q: "Aspirin (acetylsalicylic acid) is used as:", options: ["Antibiotic", "Analgesic (pain reliever) and antipyretic", "Antihistamine", "Antacid"], ans: 1, exp: "Aspirin: analgesic (relieves pain) + antipyretic (reduces fever) + anti-inflammatory. Irreversibly inhibits COX-1 and COX-2 enzymes → reduces prostaglandin synthesis. Also anti-platelet (prevents blood clots). Paracetamol: analgesic, antipyretic (not anti-inflammatory). NCERT Class 12, Ch 16.", stars: 4 },
  { id: 131, subject: "Chemistry", section: "Physical Chemistry", q: "Which of the following shows Tyndall effect?", options: ["True solution (NaCl in water)", "Colloidal solution (sol)", "Suspension", "All of the above"], ans: 1, exp: "Tyndall effect: scattering of light by colloidal particles (1–1000 nm). True solutions (< 1 nm) — NO Tyndall effect. Suspensions (> 1000 nm) — visible particles, heterogeneous. Colloids: Sol, gel, foam, emulsion. NCERT Class 12, Ch 5.", stars: 4 },
  { id: 132, subject: "Chemistry", section: "Physical Chemistry", q: "Entropy change (ΔS) during vaporization (liquid → gas) is:", options: ["Negative", "Zero", "Positive", "Cannot be determined"], ans: 2, exp: "Vaporization: liquid → gas. Disorder increases (more random arrangement, more microstates). ΔS = ΔH_vap / T_bp > 0 (Trouton's rule: ΔS_vap ≈ 88 J/mol/K for most liquids). Ice melting, sublimation, mixing of gases → ΔS > 0. NCERT Class 11, Ch 6.", stars: 4 },
  { id: 133, subject: "Chemistry", section: "Inorganic Chemistry", q: "The correct formula of bleaching powder is:", options: ["Ca(OCl)₂", "CaCl₂", "Ca(OCl)Cl", "CaO + Cl₂"], ans: 2, exp: "Bleaching powder = calcium hypochlorite mixed with calcium chloride = Ca(OCl)Cl or CaOCl₂ (mixed salt). Made by: Ca(OH)₂ + Cl₂ → Ca(OCl)Cl + H₂O. Active component: hypochlorite (OCl⁻) which releases nascent oxygen for bleaching/disinfection. NCERT Class 12, Ch 7.", stars: 4 },
  { id: 134, subject: "Chemistry", section: "Inorganic Chemistry", q: "The acidity of oxoacids of chlorine follows the order:", options: ["HClO > HClO₂ > HClO₃ > HClO₄", "HClO₄ > HClO₃ > HClO₂ > HClO", "HClO₃ > HClO₂ > HClO > HClO₄", "All have equal acidity"], ans: 1, exp: "Acidity of oxoacids: increases with number of oxygen atoms (more O → more electronegative → weaker O-H bond → more acidic). HClO₄ (perchloric) > HClO₃ (chloric) > HClO₂ (chlorous) > HClO (hypochlorous). NCERT Class 12, Ch 7.", stars: 4 },
  { id: 135, subject: "Chemistry", section: "Organic Chemistry", q: "In the following reaction: R-X + KCN → R-CN + KX, what type of reaction is this?", options: ["Electrophilic substitution", "Free radical substitution", "Nucleophilic substitution (SN2)", "Elimination"], ans: 2, exp: "CN⁻ is a strong nucleophile. CN⁻ attacks the carbon bearing the halogen (back-side attack) → displacement of X⁻ (leaving group). Product = nitrile (R-CN), which can be hydrolyzed to carboxylic acid. This reaction increases carbon chain length by 1 (useful in organic synthesis). NCERT Class 12, Ch 10.", stars: 4 },

  // PHYSICS (136-180)
  { id: 136, subject: "Physics", section: "Optics", q: "In Young's double slit experiment, if slit separation d is doubled keeping λ and D constant, fringe width β:", options: ["Doubles", "Remains same", "Halves", "Becomes four times"], ans: 2, exp: "β = λD/d. If d → 2d, β → λD/2d = β/2 (halved). If λ doubles → β doubles. If D doubles → β doubles. β is directly proportional to λ and D, inversely proportional to d. NCERT Class 12, Ch 10.", stars: 5 },
  { id: 137, subject: "Physics", section: "Optics", q: "A convex mirror of focal length f always forms:", options: ["Real, inverted image", "Virtual, erect, diminished image", "Real, erect image", "Virtual, inverted image"], ans: 1, exp: "Convex mirror: always forms virtual, erect, diminished image (regardless of object position) — image is always behind the mirror (between F and P). Used as rear-view mirror in vehicles (wider field of view). NCERT Class 12, Ch 9.", stars: 5 },
  { id: 138, subject: "Physics", section: "Modern Physics", q: "A proton and an electron have the same kinetic energy. Which has the larger de Broglie wavelength?", options: ["Proton (more massive)", "Electron (less massive)", "Both are equal", "Cannot be determined"], ans: 1, exp: "λ = h/mv = h/√(2mKE). For same KE: λ ∝ 1/√m. Mass of proton (1.67×10⁻²⁷ kg) >> electron (9.1×10⁻³¹ kg). ∴ λ_electron > λ_proton. NCERT Class 12, Ch 11.", stars: 4 },
  { id: 139, subject: "Physics", section: "Mechanics", q: "A body of mass m is projected upward with velocity v. Maximum height reached is:", options: ["v²/g", "v²/2g", "2v²/g", "v/g"], ans: 1, exp: "Energy conservation: KE = PE → ½mv² = mgh → h = v²/2g. Using kinematics: v² = u² − 2gh → 0 = v² − 2gh → h = v²/2g. At maximum height, velocity = 0. Time to reach maximum height: t = v/g. NCERT Class 11, Ch 3.", stars: 5 },
  { id: 140, subject: "Physics", section: "Mechanics", q: "The escape velocity from a planet of mass M and radius R is:", options: ["√(GM/R)", "√(2GM/R)", "√(GM/2R)", "GM/R"], ans: 1, exp: "Escape velocity: KE = PE at surface → ½mv² = GMm/R → v_e = √(2GM/R) = √(2gR) ≈ 11.2 km/s (Earth). Orbital velocity v₀ = √(GM/R) = v_e/√2. Relation: v_e = √2 × v₀. NCERT Class 11, Ch 8.", stars: 5 },
  { id: 141, subject: "Physics", section: "Electricity", q: "A charge Q is placed at the centre of a cube. The electric flux through one face of the cube is:", options: ["Q/ε₀", "Q/6ε₀", "6Q/ε₀", "Q/ε₀ × 6"], ans: 1, exp: "By Gauss's Law: total flux through closed surface = Q/ε₀. Cube has 6 equal faces. By symmetry, flux through each face = Q/6ε₀. Gauss's Law: ΦE = q_enc/ε₀ (flux = enclosed charge/permittivity). NCERT Class 12, Ch 1.", stars: 5 },
  { id: 142, subject: "Physics", section: "Modern Physics", q: "The dimensional formula of Planck's constant (h) is:", options: ["[ML²T⁻¹]", "[MLT⁻¹]", "[ML²T⁻²]", "[ML⁻¹T⁻¹]"], ans: 0, exp: "E = hf → h = E/f. [E] = ML²T⁻², [f] = T⁻¹. ∴ [h] = ML²T⁻²/T⁻¹ = ML²T⁻¹. This is also the dimension of angular momentum (L = mvr = kg·m²/s = ML²T⁻¹). Bohr's quantization: L = nh/2π. NCERT Class 11, Ch 2.", stars: 4 },
  { id: 143, subject: "Physics", section: "Mechanics", q: "For a projectile launched at angle θ with velocity u, the range R is maximum when θ equals:", options: ["30°", "45°", "60°", "90°"], ans: 1, exp: "Projectile range: R = u²sin(2θ)/g. For maximum R: sin(2θ) must be maximum = 1 → 2θ = 90° → θ = 45°. At 45°: R_max = u²/g. Complementary angles give same range: (e.g., 30° and 60° give same R). NCERT Class 11, Ch 4.", stars: 5 },
  { id: 144, subject: "Physics", section: "Electricity", q: "The SI unit of magnetic field (B) is:", options: ["Tesla (T)", "Gauss", "Weber", "Ampere/metre"], ans: 0, exp: "Magnetic field B: SI unit = Tesla (T) = Wb/m² = kg/A/s². 1 Tesla = 10⁴ Gauss (CGS). Lorentz force: F = q(v × B). Earth's magnetic field ≈ 25–65 µT. NCERT Class 12, Ch 4.", stars: 4 },
  { id: 145, subject: "Physics", section: "Modern Physics", q: "In photoelectric effect, stopping potential depends on:", options: ["Intensity of incident light", "Frequency of incident light only", "Both intensity and frequency", "Area of metal surface"], ans: 1, exp: "Stopping potential (V₀): KE_max = eV₀ = hf − φ. V₀ ∝ (f − f₀). Increasing intensity → more photoelectrons (more current) but same maximum KE → same stopping potential. Stopping potential is independent of intensity. This disproved classical wave theory of light. NCERT Class 12, Ch 11.", stars: 5 },
  { id: 146, subject: "Physics", section: "Waves", q: "The velocity of sound is MAXIMUM in:", options: ["Air at 0°C", "Air at 100°C", "Water", "Steel"], ans: 3, exp: "Speed of sound: v = √(B/ρ) (bulk modulus/density). In solids: large B, small ρ → high speed. In steel ≈ 5960 m/s. In water ≈ 1480 m/s. In air at 0°C ≈ 331 m/s, at 100°C ≈ 387 m/s. Solids > Liquids > Gases. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 147, subject: "Physics", section: "Electronics", q: "Which logic gate is called the 'universal gate'?", options: ["AND gate", "OR gate", "NAND gate", "NOT gate"], ans: 2, exp: "NAND and NOR are universal gates — any logic circuit can be made using ONLY NAND gates (or only NOR gates). NAND = NOT + AND. NOR = NOT + OR. Truth table NAND: output = 0 only when BOTH inputs = 1, otherwise output = 1. NCERT Class 12, Ch 14.", stars: 4 },
  { id: 148, subject: "Physics", section: "Mechanics", q: "Kepler's third law states that T² ∝ r³. For a satellite orbiting at radius 4R (R = Earth's radius), its time period compared to a satellite at R is:", options: ["2 times", "4 times", "8 times", "16 times"], ans: 2, exp: "Kepler's 3rd law: T² ∝ r³ → T ∝ r^(3/2). If r → 4r: T₂/T₁ = (4r/r)^(3/2) = 4^(3/2) = (2²)^(3/2) = 2³ = 8. T is 8 times longer. Geostationary satellite: T=24h, r≈6.6R. NCERT Class 11, Ch 8.", stars: 4 },
  { id: 149, subject: "Physics", section: "Electricity", q: "A transformer has 100 turns in primary and 1000 turns in secondary. If primary voltage is 110V, the secondary voltage is:", options: ["11 V", "1100 V", "110 V", "10 V"], ans: 1, exp: "Transformer equation: V_s/V_p = N_s/N_p. V_s = V_p × (N_s/N_p) = 110 × (1000/100) = 1100 V. Step-up transformer (N_s > N_p → V_s > V_p, I_s < I_p). Power: P = V_p I_p = V_s I_s (ideal transformer, 100% efficiency). NCERT Class 12, Ch 7.", stars: 4 },
  { id: 150, subject: "Physics", section: "Thermodynamics", q: "The first law of thermodynamics is a statement of:", options: ["Conservation of entropy", "Conservation of energy (ΔU = Q − W)", "Entropy always increases", "Absolute zero is unattainable"], ans: 1, exp: "First law: ΔU = Q − W. Q = heat absorbed by system, W = work done by system. ΔU = internal energy change. For isothermal process (ΔU=0): Q = W. For adiabatic (Q=0): ΔU = −W. For isochoric (W=0): ΔU = Q. Second law: entropy increases. NCERT Class 11, Ch 12.", stars: 5 },
  { id: 151, subject: "Physics", section: "Electricity", q: "A circular loop of radius r carries current I. The magnetic field at the centre is:", options: ["µ₀I/2r", "µ₀I/4πr", "µ₀I/2πr", "2µ₀I/r"], ans: 0, exp: "Magnetic field at centre of circular loop: B = µ₀I/2r. For N turns: B = Nµ₀I/2r. For a long solenoid: B = µ₀nI (n = turns per unit length). Biot-Savart law gives dB = (µ₀/4π)(I dl sinθ/r²). NCERT Class 12, Ch 4.", stars: 4 },
  { id: 152, subject: "Physics", section: "Modern Physics", q: "Which nuclear reaction releases the MOST energy per unit mass?", options: ["Nuclear fission of U-235", "Nuclear fusion of hydrogen isotopes", "Chemical combustion of coal", "All release equal energy"], ans: 1, exp: "Nuclear fusion (H + H → He + energy): releases ~3.5 MeV/nucleon. Nuclear fission: ~0.85 MeV/nucleon. Chemical reaction: ~few eV/atom. Fusion releases more energy per unit mass but requires extreme temperature (~10⁸ K) to overcome Coulomb barrier. Sun's energy = proton-proton chain fusion. NCERT Class 12, Ch 13.", stars: 4 },
  { id: 153, subject: "Physics", section: "Modern Physics", q: "The work function of a metal is 3.31 eV. The threshold frequency (f₀) is approximately: (h = 6.62 × 10⁻³⁴ J·s)", options: ["5 × 10¹⁴ Hz", "8 × 10¹⁴ Hz", "1 × 10¹⁴ Hz", "2 × 10¹⁴ Hz"], ans: 1, exp: "f₀ = φ/h = (3.31 × 1.6×10⁻¹⁹) / (6.62×10⁻³⁴) = (5.296×10⁻¹⁹) / (6.62×10⁻³⁴) ≈ 8×10¹⁴ Hz. This lies in ultraviolet region. Photons with f > f₀ cause photoelectric emission. NCERT Class 12, Ch 11.", stars: 4 },
  { id: 154, subject: "Physics", section: "Mechanics", q: "A spring of spring constant k is compressed by x. The potential energy stored is:", options: ["kx", "kx²", "½kx²", "2kx²"], ans: 2, exp: "Spring PE = ½kx² (elastic potential energy). Work done on spring = work done by spring = ½kx². For oscillating spring: Total energy = ½kA² (A = amplitude). KE = ½k(A²−x²). PE = ½kx². At equilibrium (x=0): all KE; at amplitude (x=A): all PE. NCERT Class 11, Ch 14.", stars: 4 },
  { id: 155, subject: "Physics", section: "Waves", q: "The time period of a simple pendulum is given by:", options: ["T = 2π√(l/g)", "T = 2π√(g/l)", "T = 2π√(l×g)", "T = π√(l/g)"], ans: 0, exp: "Simple pendulum: T = 2π√(l/g). Independent of mass and amplitude (small angle). Increases with l. Decreases with g (shorter period at poles where g is greater). At center of Earth: g=0, T→∞. On moon: g=1.6 m/s², T increases by factor √(6). NCERT Class 11, Ch 14.", stars: 5 },
  { id: 156, subject: "Physics", section: "Optics", q: "For a concave mirror with focal length f = 15 cm, an object is placed at 30 cm. The image distance is:", options: ["30 cm (real, inverted, same size)", "15 cm", "10 cm", "−30 cm"], ans: 0, exp: "Mirror formula: 1/v + 1/u = 1/f. u = −30 cm, f = −15 cm (concave, sign convention). 1/v = 1/f − 1/u = 1/(−15) − 1/(−30) = −1/15 + 1/30 = −2/30 + 1/30 = −1/30 → v = −30 cm. Real image at 30 cm in front of mirror. Magnification m = −v/u = −(−30)/(−30) = −1 (inverted, same size). NCERT Class 12, Ch 9.", stars: 5 },
  { id: 157, subject: "Physics", section: "Optics", q: "An object is placed at infinity in front of a convex lens (f=20cm). Where is the image formed?", options: ["At 20 cm (at focus F)", "At 40 cm", "At 10 cm", "At infinity"], ans: 0, exp: "Lens formula: 1/v − 1/u = 1/f. u = −∞ (at infinity). 1/v = 1/f + 1/u = 1/20 + 1/(−∞) = 1/20. v = 20 cm. Image forms at the focal point F (20 cm on the other side). This principle is used in astronomical telescopes and camera to focus parallel rays. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 158, subject: "Physics", section: "Electricity", q: "A current of 2A flows through a resistance of 5Ω for 10 seconds. Heat generated (Joule heating) is:", options: ["100 J", "200 J", "50 J", "400 J"], ans: 1, exp: "Joule's law: H = I²Rt = (2)² × 5 × 10 = 4 × 5 × 10 = 200 J. Also: H = V²t/R = VIt. Power P = I²R = V²/R = IV (watts). Electrical energy dissipated as heat (resistive heating). NCERT Class 12, Ch 3.", stars: 5 },
  { id: 159, subject: "Physics", section: "Modern Physics", q: "A radioactive element has a half-life of 10 years. After 30 years, the fraction remaining is:", options: ["1/4", "1/8", "1/2", "1/16"], ans: 1, exp: "Number of half-lives = 30/10 = 3. N = N₀ × (1/2)³ = N₀ × (1/2)³ = N₀/8. Fraction remaining = 1/8. Activity A = A₀ × (1/2)ⁿ. Radioactive decay: N = N₀e^(−λt), λ = 0.693/t₁/₂. NCERT Class 12, Ch 13.", stars: 5 },
  { id: 160, subject: "Physics", section: "Electronics", q: "In a p-n junction diode, current flows (forward bias) when:", options: ["p-side is connected to negative and n-side to positive terminal of battery", "p-side is connected to positive and n-side to negative terminal of battery", "No current flows regardless of connection", "Only at high voltage"], ans: 1, exp: "Forward bias: p-side (+) and n-side (−). Reduces depletion layer width → current flows (majority carriers cross junction). Reverse bias: p-side (−) and n-side (+). Increases depletion layer → only tiny reverse saturation current (minority carriers). Threshold voltage: ~0.3V (Ge), ~0.7V (Si). NCERT Class 12, Ch 14.", stars: 5 },
  { id: 161, subject: "Physics", section: "Mechanics", q: "The moment of inertia of a hollow cylinder (thin-walled) about its own axis is:", options: ["MR²/2", "MR²", "2MR²/3", "MR²/4"], ans: 1, exp: "Hollow cylinder (thin-walled ring) about axis: I = MR². Solid cylinder about axis: I = MR²/2. Hollow sphere (diameter): 2MR²/3. Solid sphere (diameter): 2MR²/5. Disc about diameter: MR²/4. NCERT Class 11, Ch 7.", stars: 4 },
  { id: 162, subject: "Physics", section: "Mechanics", q: "Which of the following correctly expresses Newton's law of gravitation?", options: ["F = GM₁M₂/r", "F = GM₁M₂/r²", "F = GM₁M₂r²", "F = G(M₁+M₂)/r²"], ans: 1, exp: "Newton's law: F = GM₁M₂/r², where G = 6.67×10⁻¹¹ N·m²/kg² (universal gravitational constant). Inverse square law. g = GM/R² (surface gravity). g decreases with altitude (∝1/r²) and below Earth's surface (∝r). NCERT Class 11, Ch 8.", stars: 4 },
  { id: 163, subject: "Physics", section: "Thermodynamics", q: "For an ideal gas, the product PV at constant temperature is:", options: ["Variable", "Constant (Boyle's Law: PV = nRT = constant)", "Proportional to T", "Equal to nRT only at STP"], ans: 1, exp: "Boyle's Law: At constant T and n, PV = constant. P₁V₁ = P₂V₂. Charles' Law: V/T = constant (constant P). Gay-Lussac's: P/T = constant (constant V). Combined: PV/T = nR = constant. Ideal gas: PV = nRT. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 164, subject: "Physics", section: "Electricity", q: "Two capacitors C₁=4µF and C₂=6µF are connected in series. The equivalent capacitance is:", options: ["10 µF", "2.4 µF", "24 µF", "0.4 µF"], ans: 1, exp: "Series capacitors: 1/C_eq = 1/C₁ + 1/C₂ = 1/4 + 1/6 = 3/12 + 2/12 = 5/12 → C_eq = 12/5 = 2.4 µF. (Note: series capacitance < smallest individual capacitor). Parallel: C_eq = C₁+C₂ = 10 µF. Energy stored: U = ½CV² = Q²/2C. NCERT Class 12, Ch 2.", stars: 4 },
  { id: 165, subject: "Physics", section: "Electricity", q: "Lenz's law is a consequence of:", options: ["Faraday's first law", "Conservation of energy", "Coulomb's law", "Biot-Savart law"], ans: 1, exp: "Lenz's law: induced current opposes the cause that produces it (change in flux). This is a consequence of conservation of energy — if induced current aided the change, it would create energy from nothing (violating energy conservation). Lenz's law and Faraday's law together: EMF = −dΦ/dt. NCERT Class 12, Ch 6.", stars: 4 },
  { id: 166, subject: "Physics", section: "Thermodynamics", q: "The rms speed of gas molecules at temperature T is proportional to:", options: ["T", "√T", "T²", "1/T"], ans: 1, exp: "Kinetic theory: v_rms = √(3RT/M) = √(3kT/m). v_rms ∝ √T. Other speeds: v_mp = √(2RT/M) (most probable), v_avg = √(8RT/πM). Relationship: v_mp < v_avg < v_rms. Ratio: 1 : 1.128 : 1.225. NCERT Class 11, Ch 13.", stars: 4 },
  { id: 167, subject: "Physics", section: "Waves", q: "The phenomenon of beating arises due to:", options: ["Diffraction", "Interference of two waves of slightly different frequencies", "Resonance", "Doppler effect"], ans: 1, exp: "Beats: superposition of two waves with frequencies f₁ and f₂ (f₁≈f₂). Beat frequency = |f₁−f₂|. The resultant amplitude alternates between maximum and minimum at beat frequency. Used in tuning musical instruments. NCERT Class 11, Ch 15.", stars: 4 },
  { id: 168, subject: "Physics", section: "Optics", q: "When white light passes through a glass prism, violet light deviates MORE than red light because:", options: ["Violet has higher wavelength", "Violet has higher frequency → higher refractive index → more bending (dispersion)", "Red light is more energetic", "Violet travels slower outside the prism"], ans: 1, exp: "Cauchy's relation: n = A + B/λ². Higher frequency (shorter λ) → higher refractive index → more bending. Violet (400nm) deviates most; red (700nm) deviates least. This is dispersion. Angular dispersion = δ_v − δ_r. Rainbows: white light dispersed by water droplets. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 169, subject: "Physics", section: "Optics", q: "An object is placed 10 cm from a concave lens of focal length −10 cm. Image distance is:", options: ["−5 cm (virtual)", "−10 cm (virtual)", "10 cm (real)", "5 cm (real)"], ans: 0, exp: "Lens formula: 1/v − 1/u = 1/f. u = −10 cm, f = −10 cm (concave). 1/v = 1/f + 1/u = 1/(−10) + 1/(−10) = −2/10 → v = −5 cm. Image is virtual (v negative), erect, diminished, on same side as object. Concave lens ALWAYS forms virtual, erect, diminished image. NCERT Class 12, Ch 9.", stars: 4 },
  { id: 170, subject: "Physics", section: "Electronics", q: "Which is the correct statement about p-type semiconductor?", options: ["It has excess electrons as majority carriers", "It has holes as majority carriers and is formed by doping with trivalent impurities (Al, Ga, In)", "It carries negative charge overall", "All trivalent impurities create excess electrons"], ans: 1, exp: "p-type: doped with trivalent impurity (Al, Ga, In) → creates holes (positive charge carriers). Majority carriers = holes; minority carriers = electrons. n-type: pentavalent impurity (P, As, Sb) → excess electrons. Majority = electrons; minority = holes. Both types are electrically neutral overall. NCERT Class 12, Ch 14.", stars: 4 },
  { id: 171, subject: "Physics", section: "Mechanics", q: "Newton's second law of motion states that:", options: ["F = mv (momentum only)", "F = ma (net force = mass × acceleration) or F = dp/dt", "Action and reaction are equal and opposite", "Inertia determines motion"], ans: 1, exp: "Newton's 2nd Law: F_net = ma = dp/dt (rate of change of momentum). Most important form: F = dp/dt. For constant mass: F = ma. 1st Law: body at rest/constant velocity if no net force (inertia). 3rd Law: action = −reaction (equal, opposite, on different bodies). NCERT Class 11, Ch 5.", stars: 4 },
  { id: 172, subject: "Physics", section: "Waves", q: "Standing waves in a string fixed at both ends have nodes at the ends. The fundamental frequency is:", options: ["v/L", "v/2L", "v/4L", "2v/L"], ans: 1, exp: "Fundamental (1st harmonic): λ₁ = 2L → f₁ = v/2L. 2nd harmonic: f₂ = v/L = 2f₁. 3rd harmonic: f₃ = 3v/2L. Open organ pipe: f₁ = v/2L (both ends open, same as string). Closed organ pipe: f₁ = v/4L (only odd harmonics). NCERT Class 11, Ch 15.", stars: 4 },
  { id: 173, subject: "Physics", section: "Modern Physics", q: "According to the Heisenberg uncertainty principle:", options: ["Position and velocity can be determined simultaneously", "Δx × Δp ≥ h/4π", "Δx × Δp = h", "Only energy is uncertain"], ans: 1, exp: "Heisenberg uncertainty principle: Δx × Δp ≥ h/4π (ℏ/2). Also: ΔE × Δt ≥ h/4π. Fundamental limitation — not due to instrument error but quantum nature. An electron cannot have zero energy (zero-point energy). Explains stability of atoms. NCERT Class 11, Ch 2.", stars: 4 },
  { id: 174, subject: "Physics", section: "Electricity", q: "An electric field E and a magnetic field B act at right angles to each other and to the velocity v of a charged particle. The particle moves undeviated if:", options: ["E = B", "v = E/B", "v = B/E", "v = EB"], ans: 1, exp: "Velocity selector: For undeviated motion, electric force = magnetic force. qE = qvB → v = E/B. This condition selects only particles with velocity v = E/B regardless of their mass or charge (used in mass spectrometer). NCERT Class 12, Ch 4.", stars: 4 },
  { id: 175, subject: "Physics", section: "Electronics", q: "The energy gap (band gap) in a conductor, semiconductor and insulator respectively is:", options: ["Large, small, zero", "Zero, small (~1 eV), large (> 3 eV)", "Small, large, zero", "All equal"], ans: 1, exp: "Band theory: Conductor: conduction band and valence band overlap → Eg ≈ 0. Semiconductor: Eg ≈ 0.7 eV (Ge), 1.1 eV (Si) — can be crossed at room temperature. Insulator: Eg > 3 eV (diamond = 5.4 eV, SiO₂ = 9 eV). NCERT Class 12, Ch 14.", stars: 4 },
  { id: 176, subject: "Physics", section: "Thermodynamics", q: "The critical temperature of a gas is the temperature:", options: ["At which it solidifies", "Above which it cannot be liquefied by pressure alone", "At which it becomes superconducting", "At which its volume is minimum"], ans: 1, exp: "Critical temperature (Tc): above Tc, gas cannot be liquefied regardless of how much pressure is applied. For liquefaction, temperature must be below Tc. Tc for CO₂ = 31.1°C, O₂ = −118.4°C, N₂ = −147.1°C. NCERT Class 11, Ch 5.", stars: 4 },
  { id: 177, subject: "Physics", section: "Waves", q: "Electromagnetic waves are transverse waves. The correct relationship between E, B, and direction of propagation (k) is:", options: ["E ∥ B ∥ k", "E ⊥ B, both ⊥ k", "E ∥ k, B ⊥ k", "E ⊥ k, B ∥ k"], ans: 1, exp: "EM waves: E ⊥ B (mutually perpendicular electric and magnetic fields), and both ⊥ to direction of propagation (k). E × B gives the direction of propagation (Poynting vector S = E × B/µ₀). Speed c = E/B = 1/√(µ₀ε₀) ≈ 3×10⁸ m/s. NCERT Class 12, Ch 8.", stars: 4 },
  { id: 178, subject: "Physics", section: "Electronics", q: "For an n-p-n transistor in the active region (common emitter), the current gain β is defined as:", options: ["IC/IE", "IC/IB", "IB/IE", "IE/IC"], ans: 1, exp: "Transistor current relations: IE = IC + IB. β (common emitter current gain) = IC/IB (typically 20–500). α (common base) = IC/IE. Relationship: β = α/(1−α). In active region: emitter-base forward biased, collector-base reverse biased. Used as amplifier (signal amplification by β). NCERT Class 12, Ch 14.", stars: 4 },
  { id: 179, subject: "Physics", section: "Modern Physics", q: "An electron in hydrogen atom transitions from n=3 to n=1. The energy of photon emitted is: (E₁ = −13.6 eV)", options: ["12.09 eV", "13.6 eV", "1.51 eV", "10.2 eV"], ans: 0, exp: "E_n = −13.6/n² eV. E₃ = −13.6/9 = −1.51 eV. E₁ = −13.6/1 = −13.6 eV. ΔE = E₃ − E₁ = −1.51 − (−13.6) = 12.09 eV (photon energy emitted). This belongs to Lyman series (UV). n=3→2: Balmer (visible, 1.89 eV). NCERT Class 12, Ch 12.", stars: 5 },
  { id: 180, subject: "Physics", section: "Electricity", q: "In Ampere's law, the line integral of B·dl around a closed loop equals:", options: ["ε₀ × flux", "µ₀ × (total current enclosed)", "µ₀ε₀ × (flux change)", "Zero always"], ans: 1, exp: "Ampere's law: ∮B·dl = µ₀I_enclosed. For a long straight wire: B × 2πr = µ₀I → B = µ₀I/2πr. Modified Ampere-Maxwell law includes displacement current: ∮B·dl = µ₀(I_c + ε₀ dΦE/dt). NCERT Class 12, Ch 4 and Ch 8.", stars: 4 },
];

const OPTION_LABELS = ["A", "B", "C", "D"];

const subjectColors = {
  "Biology": { bg: "from-emerald-900/40 to-teal-900/40", accent: "#10d4a0", light: "#6ee7b7", badge: "bg-emerald-500/20 text-emerald-300 border-emerald-500/30" },
  "Chemistry": { bg: "from-blue-900/40 to-indigo-900/40", accent: "#60a5fa", light: "#93c5fd", badge: "bg-blue-500/20 text-blue-300 border-blue-500/30" },
  "Physics": { bg: "from-orange-900/40 to-red-900/40", accent: "#fb923c", light: "#fdba74", badge: "bg-orange-500/20 text-orange-300 border-orange-500/30" },
};

export default function NEETApp() {
  const [phase, setPhase] = useState("home"); // home, exam, result
  const [current, setCurrent] = useState(0);
  const [answers, setAnswers] = useState({}); // { qId: selectedIndex }
  const [revealed, setRevealed] = useState({}); // { qId: true }
  const [timeLeft, setTimeLeft] = useState(180 * 60);
  const [filter, setFilter] = useState("All");
  const timerRef = useRef(null);

  useEffect(() => {
    if (phase === "exam") {
      timerRef.current = setInterval(() => {
        setTimeLeft(t => {
          if (t <= 1) {
            clearInterval(timerRef.current);
            setPhase("result");
            return 0;
          }
          return t - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [phase]);

  const formatTime = (s) => {
    const h = Math.floor(s / 3600);
    const m = Math.floor((s % 3600) / 60);
    const sec = s % 60;
    return `${h}:${String(m).padStart(2, "0")}:${String(sec).padStart(2, "0")}`;
  };

  const filteredQs = filter === "All" ? questions : questions.filter(q => q.subject === filter);
  const currentQ = filteredQs[current];

  const handleSelect = (idx) => {
    if (revealed[currentQ.id]) return;
    const newAnswers = { ...answers, [currentQ.id]: idx };
    setAnswers(newAnswers);
    const newRevealed = { ...revealed, [currentQ.id]: true };
    setRevealed(newRevealed);
  };

  const calcScore = () => {
    let score = 0, correct = 0, wrong = 0, unattempted = 0;
    questions.forEach(q => {
      if (answers[q.id] === undefined) { unattempted++; }
      else if (answers[q.id] === q.ans) { correct++; score += 4; }
      else { wrong++; score -= 1; }
    });
    return { score, correct, wrong, unattempted };
  };

  const subjectStats = () => {
    const subjects = ["Biology", "Chemistry", "Physics"];
    return subjects.map(sub => {
      const qs = questions.filter(q => q.subject === sub);
      let correct = 0, wrong = 0, unattempted = 0;
      qs.forEach(q => {
        if (answers[q.id] === undefined) unattempted++;
        else if (answers[q.id] === q.ans) correct++;
        else wrong++;
      });
      return { subject: sub, correct, wrong, unattempted, total: qs.length };
    });
  };

  if (phase === "home") {
    return (
      <div style={{ fontFamily: "'Georgia', serif", minHeight: "100vh", background: "linear-gradient(135deg, #0a0a0f 0%, #0d1117 50%, #0a0f1a 100%)", color: "#e2e8f0", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "2rem", position: "relative", overflow: "hidden" }}>
        {/* Decorative circles */}
        <div style={{ position: "absolute", top: "-200px", left: "-200px", width: "600px", height: "600px", borderRadius: "50%", background: "radial-gradient(circle, rgba(16,212,160,0.06) 0%, transparent 70%)", pointerEvents: "none" }} />
        <div style={{ position: "absolute", bottom: "-200px", right: "-200px", width: "600px", height: "600px", borderRadius: "50%", background: "radial-gradient(circle, rgba(96,165,250,0.06) 0%, transparent 70%)", pointerEvents: "none" }} />
        
        <div style={{ textAlign: "center", maxWidth: "720px", zIndex: 1 }}>
          <div style={{ fontSize: "0.75rem", letterSpacing: "0.3em", textTransform: "uppercase", color: "#10d4a0", marginBottom: "1rem", fontFamily: "monospace" }}>PREDICTED PAPER · MAY 3, 2026</div>
          <h1 style={{ fontSize: "clamp(2.5rem, 6vw, 4.5rem)", fontWeight: "900", lineHeight: 1.1, margin: "0 0 0.5rem", background: "linear-gradient(135deg, #f8fafc 0%, #94a3b8 100%)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>NEET UG 2026</h1>
          <h2 style={{ fontSize: "clamp(1rem, 2.5vw, 1.5rem)", fontWeight: "400", color: "#64748b", letterSpacing: "0.15em", textTransform: "uppercase", marginBottom: "2.5rem" }}>Mock Test · Full Syllabus</h2>
          
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "1rem", marginBottom: "2.5rem" }}>
            {[
              { label: "Questions", value: "180", color: "#10d4a0" },
              { label: "Duration", value: "3 Hours", color: "#60a5fa" },
              { label: "Max Marks", value: "720", color: "#fb923c" },
            ].map(s => (
              <div key={s.label} style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: "12px", padding: "1.25rem 1rem" }}>
                <div style={{ fontSize: "1.75rem", fontWeight: "700", color: s.color, lineHeight: 1 }}>{s.value}</div>
                <div style={{ fontSize: "0.75rem", color: "#64748b", marginTop: "0.25rem", textTransform: "uppercase", letterSpacing: "0.1em" }}>{s.label}</div>
              </div>
            ))}
          </div>

          <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: "12px", padding: "1.25rem", marginBottom: "2.5rem", textAlign: "left" }}>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: "0.75rem", fontSize: "0.85rem" }}>
              {[
                { subject: "Biology", qs: "90 Qs", marks: "360 Marks", color: "#10d4a0" },
                { subject: "Chemistry", qs: "45 Qs", marks: "180 Marks", color: "#60a5fa" },
                { subject: "Physics", qs: "45 Qs", marks: "180 Marks", color: "#fb923c" },
              ].map(s => (
                <div key={s.subject} style={{ padding: "0.75rem", borderRadius: "8px", border: `1px solid ${s.color}30`, background: `${s.color}08` }}>
                  <div style={{ color: s.color, fontWeight: "600", marginBottom: "0.25rem" }}>{s.subject}</div>
                  <div style={{ color: "#94a3b8", fontSize: "0.75rem" }}>{s.qs} · {s.marks}</div>
                </div>
              ))}
            </div>
            <div style={{ marginTop: "1rem", paddingTop: "1rem", borderTop: "1px solid rgba(255,255,255,0.06)", display: "flex", gap: "2rem", justifyContent: "center", fontSize: "0.8rem", color: "#64748b" }}>
              <span>✓ Correct: <span style={{ color: "#10d4a0", fontWeight: 600 }}>+4 marks</span></span>
              <span>✗ Wrong: <span style={{ color: "#f87171", fontWeight: 600 }}>−1 mark</span></span>
              <span>— Unattempted: <span style={{ color: "#94a3b8", fontWeight: 600 }}>0 marks</span></span>
            </div>
          </div>

          <button onClick={() => setPhase("exam")} style={{ background: "linear-gradient(135deg, #10d4a0, #0ea5e9)", border: "none", color: "white", padding: "1rem 3.5rem", fontSize: "1.1rem", fontWeight: "700", borderRadius: "50px", cursor: "pointer", letterSpacing: "0.1em", textTransform: "uppercase", boxShadow: "0 0 40px rgba(16,212,160,0.3)", transition: "all 0.3s" }}
            onMouseOver={e => e.target.style.transform = "scale(1.04)"}
            onMouseOut={e => e.target.style.transform = "scale(1)"}
          >
            Begin Exam
          </button>
          <p style={{ marginTop: "1rem", fontSize: "0.75rem", color: "#475569" }}>Based on 16-year NEET/AIPMT deep analysis · All questions from PDF</p>
        </div>
      </div>
    );
  }

  if (phase === "result") {
    const { score, correct, wrong, unattempted } = calcScore();
    const stats = subjectStats();
    const pct = Math.round((score / 720) * 100);
    const rank = score >= 600 ? "🏆 AIR < 1000" : score >= 550 ? "🥇 Gov. Medical College" : score >= 450 ? "🥈 State Quota" : score >= 300 ? "🥉 Private Medical" : "📚 Need More Practice";
    
    return (
      <div style={{ fontFamily: "'Georgia', serif", minHeight: "100vh", background: "linear-gradient(135deg, #0a0a0f 0%, #0d1117 50%, #0a0f1a 100%)", color: "#e2e8f0", padding: "2rem 1rem" }}>
        <div style={{ maxWidth: "860px", margin: "0 auto" }}>
          <div style={{ textAlign: "center", marginBottom: "2rem" }}>
            <div style={{ fontSize: "0.7rem", letterSpacing: "0.3em", color: "#64748b", textTransform: "uppercase", marginBottom: "0.5rem", fontFamily: "monospace" }}>NEET UG 2026 · PREDICTED PAPER</div>
            <h1 style={{ fontSize: "2.5rem", fontWeight: "900", margin: "0 0 0.25rem", background: "linear-gradient(135deg, #f8fafc, #94a3b8)", WebkitBackgroundClip: "text", WebkitTextFillColor: "transparent" }}>Your Results</h1>
          </div>

          {/* Score Card */}
          <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.08)", borderRadius: "20px", padding: "2rem", marginBottom: "1.5rem", textAlign: "center" }}>
            <div style={{ fontSize: "5rem", fontWeight: "900", lineHeight: 1, color: score >= 550 ? "#10d4a0" : score >= 300 ? "#fb923c" : "#f87171" }}>{score}</div>
            <div style={{ fontSize: "1rem", color: "#64748b", marginBottom: "0.5rem" }}>out of 720</div>
            <div style={{ fontSize: "1.25rem", marginBottom: "1.5rem" }}>{rank}</div>
            <div style={{ width: "100%", height: "8px", background: "rgba(255,255,255,0.08)", borderRadius: "4px", overflow: "hidden" }}>
              <div style={{ height: "100%", borderRadius: "4px", width: `${Math.max(0, Math.min(100, (score/720)*100))}%`, background: score >= 550 ? "linear-gradient(90deg, #10d4a0, #0ea5e9)" : score >= 300 ? "linear-gradient(90deg, #fb923c, #f59e0b)" : "linear-gradient(90deg, #f87171, #ec4899)", transition: "width 1s" }} />
            </div>
            <div style={{ marginTop: "0.5rem", fontSize: "0.8rem", color: "#64748b" }}>{pct}% scored</div>
          </div>

          {/* Stats row */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: "1rem", marginBottom: "1.5rem" }}>
            {[
              { label: "Correct", value: correct, color: "#10d4a0", marks: `+${correct * 4}` },
              { label: "Wrong", value: wrong, color: "#f87171", marks: `-${wrong}` },
              { label: "Unattempted", value: unattempted, color: "#64748b", marks: "0" },
            ].map(s => (
              <div key={s.label} style={{ background: "rgba(255,255,255,0.03)", border: `1px solid ${s.color}30`, borderRadius: "12px", padding: "1.25rem", textAlign: "center" }}>
                <div style={{ fontSize: "2rem", fontWeight: "700", color: s.color }}>{s.value}</div>
                <div style={{ fontSize: "0.75rem", color: "#64748b", textTransform: "uppercase", letterSpacing: "0.1em" }}>{s.label}</div>
                <div style={{ fontSize: "0.85rem", color: s.color, marginTop: "0.25rem", fontFamily: "monospace" }}>{s.marks} marks</div>
              </div>
            ))}
          </div>

          {/* Subject breakdown */}
          <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: "16px", padding: "1.5rem", marginBottom: "1.5rem" }}>
            <h3 style={{ margin: "0 0 1rem", fontSize: "0.8rem", letterSpacing: "0.2em", textTransform: "uppercase", color: "#64748b" }}>Subject Breakdown</h3>
            {stats.map(s => {
              const c = subjectColors[s.subject];
              const acc = Math.round((s.correct / s.total) * 100);
              return (
                <div key={s.subject} style={{ marginBottom: "1rem" }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "0.5rem" }}>
                    <span style={{ fontWeight: "600", color: c.accent }}>{s.subject}</span>
                    <span style={{ fontSize: "0.8rem", color: "#64748b" }}>{s.correct}/{s.total} correct · {acc}%</span>
                  </div>
                  <div style={{ width: "100%", height: "6px", background: "rgba(255,255,255,0.08)", borderRadius: "3px", overflow: "hidden" }}>
                    <div style={{ height: "100%", width: `${acc}%`, background: c.accent, borderRadius: "3px", transition: "width 1s" }} />
                  </div>
                  <div style={{ display: "flex", gap: "1rem", marginTop: "0.4rem", fontSize: "0.72rem", color: "#64748b" }}>
                    <span style={{ color: "#10d4a0" }}>✓ {s.correct}</span>
                    <span style={{ color: "#f87171" }}>✗ {s.wrong}</span>
                    <span>— {s.unattempted}</span>
                  </div>
                </div>
              );
            })}
          </div>

          <div style={{ display: "flex", gap: "1rem", justifyContent: "center" }}>
            <button onClick={() => { setPhase("home"); setAnswers({}); setRevealed({}); setCurrent(0); setTimeLeft(180*60); setFilter("All"); }} style={{ background: "rgba(255,255,255,0.05)", border: "1px solid rgba(255,255,255,0.1)", color: "#e2e8f0", padding: "0.75rem 2rem", borderRadius: "50px", cursor: "pointer", fontSize: "0.9rem", fontWeight: "600" }}>
              Retake Exam
            </button>
            <button onClick={() => { setPhase("review"); setCurrent(0); }} style={{ background: "linear-gradient(135deg, #10d4a0, #0ea5e9)", border: "none", color: "white", padding: "0.75rem 2rem", borderRadius: "50px", cursor: "pointer", fontSize: "0.9rem", fontWeight: "700" }}>
              Review Answers
            </button>
          </div>
        </div>
      </div>
    );
  }

  // EXAM & REVIEW phase
  const isReview = phase === "review";
  const q = currentQ;
  const selectedAns = answers[q.id];
  const isAnswered = selectedAns !== undefined;
  const isCorrect = selectedAns === q.ans;
  const showExplanation = isReview || revealed[q.id];
  const col = subjectColors[q.subject];

  const attempted = Object.keys(answers).length;
  const { score } = calcScore();

  return (
    <div style={{ fontFamily: "'Georgia', serif", minHeight: "100vh", background: "linear-gradient(135deg, #0a0a0f 0%, #0d1117 100%)", color: "#e2e8f0", display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ position: "sticky", top: 0, zIndex: 10, background: "rgba(10,10,15,0.95)", backdropFilter: "blur(10px)", borderBottom: "1px solid rgba(255,255,255,0.07)", padding: "0.75rem 1rem" }}>
        <div style={{ maxWidth: "1100px", margin: "0 auto", display: "flex", alignItems: "center", gap: "0.75rem", flexWrap: "wrap" }}>
          <div style={{ fontSize: "0.75rem", fontWeight: "700", letterSpacing: "0.2em", color: "#64748b", textTransform: "uppercase", flexShrink: 0, fontFamily: "monospace" }}>NEET 2026</div>
          
          {/* Subject filter */}
          <div style={{ display: "flex", gap: "0.4rem", flexWrap: "wrap" }}>
            {["All", "Biology", "Chemistry", "Physics"].map(f => (
              <button key={f} onClick={() => { setFilter(f); setCurrent(0); }} style={{ padding: "0.3rem 0.75rem", borderRadius: "50px", border: `1px solid ${filter === f ? col.accent : "rgba(255,255,255,0.1)"}`, background: filter === f ? `${col.accent}20` : "transparent", color: filter === f ? col.accent : "#64748b", fontSize: "0.72rem", cursor: "pointer", fontWeight: filter === f ? "700" : "400", transition: "all 0.2s" }}>
                {f}
              </button>
            ))}
          </div>

          <div style={{ marginLeft: "auto", display: "flex", alignItems: "center", gap: "1rem", flexShrink: 0 }}>
            {!isReview && (
              <div style={{ fontFamily: "monospace", fontSize: "0.9rem", color: timeLeft < 600 ? "#f87171" : "#10d4a0", fontWeight: "700", minWidth: "5rem", textAlign: "right" }}>⏱ {formatTime(timeLeft)}</div>
            )}
            <div style={{ fontSize: "0.75rem", color: "#64748b", fontFamily: "monospace" }}>
              {attempted}/180 · <span style={{ color: score >= 0 ? "#10d4a0" : "#f87171" }}>{score > 0 ? "+" : ""}{score}</span>
            </div>
            {!isReview && (
              <button onClick={() => { clearInterval(timerRef.current); setPhase("result"); }} style={{ padding: "0.4rem 1rem", borderRadius: "50px", background: "rgba(248,113,113,0.15)", border: "1px solid rgba(248,113,113,0.3)", color: "#f87171", fontSize: "0.75rem", cursor: "pointer", fontWeight: "600" }}>
                Submit
              </button>
            )}
            {isReview && (
              <button onClick={() => setPhase("result")} style={{ padding: "0.4rem 1rem", borderRadius: "50px", background: "rgba(16,212,160,0.15)", border: "1px solid rgba(16,212,160,0.3)", color: "#10d4a0", fontSize: "0.75rem", cursor: "pointer", fontWeight: "600" }}>
                ← Results
              </button>
            )}
          </div>
        </div>
      </div>

      <div style={{ flex: 1, maxWidth: "1100px", margin: "0 auto", width: "100%", padding: "1.5rem 1rem", display: "grid", gridTemplateColumns: "1fr minmax(200px, 240px)", gap: "1.5rem", alignItems: "start" }}>
        {/* Question Panel */}
        <div>
          {/* Q Header */}
          <div style={{ display: "flex", alignItems: "center", gap: "0.75rem", marginBottom: "1rem", flexWrap: "wrap" }}>
            <span style={{ background: `${col.accent}25`, color: col.accent, border: `1px solid ${col.accent}40`, borderRadius: "6px", padding: "0.25rem 0.6rem", fontSize: "0.72rem", fontWeight: "700", textTransform: "uppercase", letterSpacing: "0.1em" }}>Q {q.id}</span>
            <span style={{ background: "rgba(255,255,255,0.05)", color: "#94a3b8", border: "1px solid rgba(255,255,255,0.08)", borderRadius: "6px", padding: "0.25rem 0.6rem", fontSize: "0.72rem" }}>{q.subject}</span>
            <span style={{ background: "rgba(255,255,255,0.05)", color: "#94a3b8", border: "1px solid rgba(255,255,255,0.08)", borderRadius: "6px", padding: "0.25rem 0.6rem", fontSize: "0.72rem" }}>{q.section}</span>
            <span style={{ marginLeft: "auto", color: "#fb923c", fontSize: "0.8rem" }}>{"★".repeat(q.stars)}</span>
          </div>

          {/* Question */}
          <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: "16px", padding: "1.5rem", marginBottom: "1rem" }}>
            <p style={{ margin: 0, fontSize: "1.05rem", lineHeight: 1.65, fontWeight: "500" }}>{q.q}</p>
          </div>

          {/* Options */}
          <div style={{ display: "flex", flexDirection: "column", gap: "0.6rem", marginBottom: "1rem" }}>
            {q.options.map((opt, idx) => {
              let bg = "rgba(255,255,255,0.03)";
              let border = "1px solid rgba(255,255,255,0.07)";
              let textColor = "#e2e8f0";
              let labelColor = "#64748b";
              let badge = null;

              if (showExplanation) {
                if (idx === q.ans) {
                  bg = "rgba(16,212,160,0.1)";
                  border = "1px solid rgba(16,212,160,0.4)";
                  textColor = "#d1fae5";
                  labelColor = "#10d4a0";
                  badge = <span style={{ marginLeft: "auto", background: "#10d4a020", color: "#10d4a0", border: "1px solid #10d4a040", borderRadius: "4px", padding: "0.1rem 0.5rem", fontSize: "0.65rem", fontWeight: "700" }}>CORRECT</span>;
                } else if (isAnswered && idx === selectedAns && selectedAns !== q.ans) {
                  bg = "rgba(248,113,113,0.1)";
                  border = "1px solid rgba(248,113,113,0.4)";
                  textColor = "#fee2e2";
                  labelColor = "#f87171";
                  badge = <span style={{ marginLeft: "auto", background: "#f8717120", color: "#f87171", border: "1px solid #f8717140", borderRadius: "4px", padding: "0.1rem 0.5rem", fontSize: "0.65rem", fontWeight: "700" }}>WRONG</span>;
                }
              } else if (isAnswered && idx === selectedAns) {
                bg = `${col.accent}15`;
                border = `1px solid ${col.accent}50`;
                labelColor = col.accent;
              }

              return (
                <button key={idx} onClick={() => handleSelect(idx)} style={{ display: "flex", alignItems: "flex-start", gap: "0.75rem", padding: "1rem 1.25rem", borderRadius: "12px", background: bg, border, color: textColor, textAlign: "left", cursor: showExplanation ? "default" : "pointer", transition: "all 0.15s", fontSize: "0.95rem", lineHeight: 1.55, width: "100%" }}
                  onMouseOver={e => { if (!showExplanation && !isAnswered) { e.currentTarget.style.background = `${col.accent}10`; e.currentTarget.style.border = `1px solid ${col.accent}30`; }}}
                  onMouseOut={e => { if (!showExplanation && !isAnswered) { e.currentTarget.style.background = bg; e.currentTarget.style.border = border; }}}
                >
                  <span style={{ minWidth: "1.5rem", height: "1.5rem", borderRadius: "50%", background: `${labelColor}20`, color: labelColor, display: "flex", alignItems: "center", justifyContent: "center", fontSize: "0.7rem", fontWeight: "700", flexShrink: 0, marginTop: "0.05rem" }}>{OPTION_LABELS[idx]}</span>
                  <span style={{ flex: 1 }}>{opt}</span>
                  {badge}
                </button>
              );
            })}
          </div>

          {/* Explanation */}
          {showExplanation && (
            <div style={{ background: isCorrect || isReview ? "rgba(16,212,160,0.06)" : "rgba(248,113,113,0.06)", border: `1px solid ${isCorrect || isReview ? "rgba(16,212,160,0.2)" : "rgba(248,113,113,0.2)"}`, borderRadius: "12px", padding: "1.25rem" }}>
              {isAnswered && !isReview && (
                <div style={{ fontWeight: "700", marginBottom: "0.75rem", fontSize: "0.95rem", color: isCorrect ? "#10d4a0" : "#f87171" }}>
                  {isCorrect ? "✅ Correct! +4 marks" : "❌ Incorrect. −1 mark"}
                </div>
              )}
              <div style={{ fontSize: "0.875rem", lineHeight: 1.7, color: "#94a3b8" }}>
                <span style={{ fontWeight: "600", color: "#e2e8f0" }}>Explanation: </span>{q.exp}
              </div>
            </div>
          )}

          {/* Nav buttons */}
          <div style={{ display: "flex", gap: "0.75rem", marginTop: "1.25rem" }}>
            <button onClick={() => setCurrent(c => Math.max(0, c - 1))} disabled={current === 0} style={{ flex: 1, padding: "0.75rem", borderRadius: "10px", background: current === 0 ? "rgba(255,255,255,0.02)" : "rgba(255,255,255,0.06)", border: "1px solid rgba(255,255,255,0.08)", color: current === 0 ? "#334155" : "#e2e8f0", cursor: current === 0 ? "not-allowed" : "pointer", fontSize: "0.9rem", fontWeight: "600" }}>
              ← Previous
            </button>
            <button onClick={() => setCurrent(c => Math.min(filteredQs.length - 1, c + 1))} disabled={current === filteredQs.length - 1} style={{ flex: 1, padding: "0.75rem", borderRadius: "10px", background: current === filteredQs.length - 1 ? "rgba(255,255,255,0.02)" : `${col.accent}20`, border: `1px solid ${current === filteredQs.length - 1 ? "rgba(255,255,255,0.08)" : col.accent + "40"}`, color: current === filteredQs.length - 1 ? "#334155" : col.accent, cursor: current === filteredQs.length - 1 ? "not-allowed" : "pointer", fontSize: "0.9rem", fontWeight: "600" }}>
              Next →
            </button>
          </div>
        </div>

        {/* Sidebar — Question Grid */}
        <div style={{ position: "sticky", top: "70px" }}>
          <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: "14px", padding: "1rem" }}>
            <div style={{ fontSize: "0.7rem", textTransform: "uppercase", letterSpacing: "0.15em", color: "#64748b", marginBottom: "0.75rem" }}>Question Navigator</div>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(6, 1fr)", gap: "4px", maxHeight: "460px", overflowY: "auto" }}>
              {filteredQs.map((fq, idx) => {
                const isAns = answers[fq.id] !== undefined;
                const isCor = answers[fq.id] === fq.ans;
                const isCur = idx === current;
                let bg, borderC;
                if (isCur) { bg = col.accent; borderC = col.accent; }
                else if (!isAns) { bg = "rgba(255,255,255,0.04)"; borderC = "rgba(255,255,255,0.08)"; }
                else if (isCor) { bg = "rgba(16,212,160,0.2)"; borderC = "#10d4a070"; }
                else { bg = "rgba(248,113,113,0.2)"; borderC = "#f8717170"; }
                return (
                  <button key={fq.id} onClick={() => setCurrent(idx)} style={{ aspectRatio: "1", borderRadius: "5px", background: bg, border: `1px solid ${borderC}`, color: isCur ? "#0a0a0f" : "#e2e8f0", fontSize: "0.62rem", fontWeight: isCur ? "700" : "500", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", transition: "all 0.1s" }}>
                    {fq.id}
                  </button>
                );
              })}
            </div>
            <div style={{ marginTop: "0.75rem", borderTop: "1px solid rgba(255,255,255,0.06)", paddingTop: "0.75rem", display: "flex", flexDirection: "column", gap: "0.3rem", fontSize: "0.68rem", color: "#64748b" }}>
              <div style={{ display: "flex", gap: "0.4rem", alignItems: "center" }}><div style={{ width: "10px", height: "10px", borderRadius: "3px", background: "rgba(16,212,160,0.2)", border: "1px solid #10d4a070" }} /> Correct</div>
              <div style={{ display: "flex", gap: "0.4rem", alignItems: "center" }}><div style={{ width: "10px", height: "10px", borderRadius: "3px", background: "rgba(248,113,113,0.2)", border: "1px solid #f8717170" }} /> Wrong</div>
              <div style={{ display: "flex", gap: "0.4rem", alignItems: "center" }}><div style={{ width: "10px", height: "10px", borderRadius: "3px", background: "rgba(255,255,255,0.04)", border: "1px solid rgba(255,255,255,0.08)" }} /> Not Attempted</div>
            </div>
          </div>

          {/* Live score card */}
          <div style={{ background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.07)", borderRadius: "14px", padding: "1rem", marginTop: "1rem" }}>
            <div style={{ fontSize: "0.7rem", textTransform: "uppercase", letterSpacing: "0.15em", color: "#64748b", marginBottom: "0.75rem" }}>Live Score</div>
            <div style={{ fontSize: "2.5rem", fontWeight: "900", color: score >= 0 ? "#10d4a0" : "#f87171", lineHeight: 1, textAlign: "center" }}>{score}</div>
            <div style={{ textAlign: "center", fontSize: "0.75rem", color: "#64748b", marginBottom: "0.75rem" }}>/ 720 marks</div>
            <div style={{ fontSize: "0.72rem", color: "#64748b", textAlign: "center" }}>{attempted} answered · {180 - attempted} remaining</div>
          </div>
        </div>
      </div>
    </div>
  );
}
